-- IDEA 8: 律所咨询登记系统 - Author 2
-- ============================================================
INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(8, 2, E'# 律所前台通 - 小型律师事务所咨询管理系统\n\n## 1. 产品概述\n\n律所前台通是专为 3-8 人小型律师事务所打造的来访咨询管理 SaaS 工具，解决小律所在「咨询登记混乱、案件分配低效、跟进节点遗漏」三大核心痛点。产品以「前台登记→律师分配→案件追踪→自动提醒」四步工作流为核心，将律所日常案件管理从碎片化的微信/纸质记录升级为系统化的数字化管理。\n\n**产品定位**：不是大所的 OA 系统，而是小所的「数字化前台助理」。\n\n**背景洞察**：中国有约 3.8 万家律师事务所，其中 3-8 人规模的小律所占比约 65%，这类小律所普遍缺乏 IT 预算和技术人员，但面临着与大所同样的案件管理压力。\n\n## 2. 市场分析\n\n| 指标 | 数据 | 备注 |\n|------|------|------|\n| 全国律师事务所总数 | 约 3.8 万家 | 司法部 2023 年数据 |\n| 3-8 人小律所数量 | 约 2.5 万家 | 占比 65% |\n| 律所年均 IT 支出 | <2 万元（小所）| 极低，主要是微信 |\n| 人均年咨询量（小律所）| 约 200-500 件 | 含电话和来访 |\n| 因管理疏漏导致客户投诉率 | 约 15% | 律师协会统计 |\n| 愿意为管理工具付费的律所 | 约 40%（N=50）| 有需求但不知道有产品 |\n| 目标 TAM | 约 1.5 亿元/年 | 2.5 万家 × 6,000 元/年 |\n\n**政策背景**：近年法律服务市场持续扩大，人民对法律服务的需求年均增长 12%，小律所服务数量快速增长，但管理能力跟不上，导致服务质量参差不齐。司法部推动律所规范化管理，为 SaaS 工具进入提供政策背景。\n\n## 3. 竞品矩阵\n\n| 产品 | 类型 | 目标用户 | 小律所适配 | 月费 | 核心缺陷 |\n|------|------|---------|----------|------|--------|\n| iManage | 法律文档管理 | 大型律所 | 极低 | $100+/人 | 太贵太重 |\n| 律驰（中国）| 律所管理 OA | 中大律所 | 低 | ¥500+/月 | 功能复杂，需培训 |\n| 法大大 | 电子合同 | 全行业 | 中 | 按次计费 | 非案件管理工具 |\n| 钉钉/飞书 | 通用协作 | 企业通用 | 中 | ¥0-30/人 | 需大量自定义，无法律专属功能 |\n| 纸质登记本 | 传统方式 | 小律所 | 高（现状）| 免费 | 无法搜索、易丢失、不可追踪 |\n| **律所前台通** | **小律所专属** | **3-8 人律所** | **极高** | **¥199/月** | **新品牌** |\n\n## 4. 目标用户画像\n\n### 画像 A：「忙碌合伙人」- 陈律师\n- **基本信息**：42 岁，合伙人，上海，管理 6 人律所（含 3 名律师，2 名助理，1 名前台）\n- **工作现状**：每天接待 5-10 个新咨询，案子多的时候靠记忆和纸质便条追进度\n- **最怕的事**：客户打电话来问「我的案子进展怎么样」，当场答不上来\n- **核心痛点**：\n  1. 三名律师各管各的案子，主任不知道整体进度\n  2. 客户跟进提醒靠手机备忘录，经常忘\n  3. 新咨询客户信息散落在微信、纸条和脑子里\n- **付费决策**：只要能让律所「看起来更专业」，400 元/月以内他愿意付\n\n### 画像 B：「精细管理型」前台 - 小李\n- **年龄**：24 岁，律所前台，实际负责所有案件登记和跟进\n- **日常工作**：接待来访客户 → 记录咨询信息 → 通知律师 → 跟进进度 → 提醒客户\n- **核心困境**：全靠自己的记忆和微信消息，担心漏掉重要事项\n- **核心需求**：\n  - 有一个系统能记录每个客户的情况，不需要靠记忆\n  - 能自动提醒需要跟进的案件\n  - 出问题时有记录可查\n- **产品使用特征**：主要使用者，需要简单易上手\n\n### 画像 C：「合规意识强」的年轻律师 - 赵晓雯\n- **年龄**：30 岁，执业 3 年，专注家事法\n- **痛点**：案件周期长（3-18 个月），节点太多，靠手工提醒容易漏\n- **核心需求**：能自动提醒每个案件的关键时间节点（开庭日期/答辩截止/证据提交）\n- **对产品的期望**：像一个「法律专属的任务管理系统」\n\n## 5. 核心功能设计\n\n### P0 - MVP\n\n| 功能 | 描述 | 验收标准 |\n|------|------|--------|\n| 来访咨询登记 | 前台输入客户信息（姓名/手机/事由/来访时间）| 登记完成 <2 分钟 |\n| 律师分配 | 选择负责律师，发送分配通知 | 分配通知实时送达（微信/短信）|\n| 案件状态追踪 | 咨询→评估→签约→进行中→结案，状态可视化 | 支持批量查看所有案件 |\n| 跟进提醒 | 设置跟进日期，到期自动提醒律师 | 提醒送达率 >98% |\n\n### P1 - 一期迭代\n\n| 功能 | 描述 | 优先级理由 |\n|------|------|----------|\n| 客户档案 | 历史案件记录、联系记录、重要事项标注 | 律师查询客户历史的核心需求 |\n| 关键节点日历 | 开庭/截止日期在日历上可视化展示 | 避免因日期遗漏造成严重后果 |\n| 案件文件附件 | 每个案件可上传相关文件 | 信息集中，减少文件找不到 |\n| 统计报表 | 月度咨询量、签约率、律师工作量分布 | 合伙人管理决策依据 |\n\n### P2 - 后续规划\n\n| 功能 | 价值 |\n|------|------|\n| 客户自助进度查询 | 给客户发链接，自助查看案件进度，减少电话 |\n| 电子合同模板 | 内置常见委托合同模板，一键生成 |\n| 收费管理 | 咨询费/律师费记录和催收提醒 |\n| 移动端 App | 律师外出也能查看和操作 |\n\n## 6. 技术架构\n\n```\n前端：\n  - Web 管理端：Vue 3 + Element Plus（PC 端，律所工作电脑）\n  - 移动端：响应式 H5（律师外出查看）\n\n后端：\n  - API 服务：Go + Echo v4\n  - 定时任务：Cron（跟进提醒、节点提醒）\n  - 通知服务：企业微信机器人 + 短信双通道\n\n存储：\n  - PostgreSQL 16（案件数据，强一致性）\n  - Redis（会话 + 缓存）\n  - 阿里云 OSS（文件附件存储）\n\n安全（律所数据敏感性高）：\n  - 数据加密存储（AES-256）\n  - 操作日志（完整审计追踪）\n  - 多律所数据严格隔离\n  - 支持私有化部署（旗舰版）\n```\n\n**数据安全是律所用户的核心顾虑**，方案中必须强调等保二级认证、数据不出境、支持私有化部署等安全承诺。\n\n## 7. 商业模式\n\n| 版本 | 月费 | 人数限制 | 核心功能 | 目标 |\n|------|------|---------|---------|------|\n| 基础版 | ¥199/月 | ≤5 人 | 登记+分配+追踪+提醒 | 3-5 人小所 |\n| 专业版 | ¥399/月 | ≤10 人 | 基础+文件+统计+节点日历 | 5-8 人律所 |\n| 旗舰版 | ¥799/月 | 无限制 | 专业+收费管理+私有化部署 | 10 人以下全功能 |\n| 私有部署 | ¥15,000/次（一次性）| 无限制 | 全功能，本地部署 | 数据合规要求高 |\n\n## 8. MVP 路线图\n\n| 时间 | 阶段 | 目标 |\n|------|------|------|\n| 第 1 月 | 调研 | 访谈 20 家小律所，确认需求 |\n| 第 2-3 月 | 开发 | P0 功能完成 |\n| 第 4 月 | 内测 | 10 家律所内测，收集反馈 |\n| 第 5-6 月 | 公测+商业化 | 开放注册，目标付费 50 家 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 |\n|------|----------|\n| 注册律所 | ≥200 |\n| 付费律所 | ≥60 |\n| MRR | ¥15,000 |\n| 咨询登记数量 | >10,000 条 |\n| NPS | ≥45 |\n| 月续费率 | ≥90% |\n\n## 10. 风险与应对\n\n| 风险 | 严重度 | 应对策略 |\n|------|-------|--------|\n| 律所数据安全顾虑极高 | 极高 | 首期就做等保二级，强调数据加密和隔离，提供私有化选项 |\n| 律师使用意愿低（觉得繁琐）| 高 | 移动端简化操作，日常操作不超过 3 步 |\n| 获客渠道单一 | 中 | 通过律师协会、法律培训机构合作推广 |\n| 合规风险（处理客户敏感信息）| 高 | 律师事务所是信息处理主体，产品合规声明明确 |',
'[{"step":"产品定位","decision":"小律所专属，不做大所OA","reason":"大所市场已有成熟产品，小所是无人服务的蓝海，差异化清晰"},{"step":"安全设计","decision":"第一版就做数据加密和隔离","reason":"律所数据极度敏感，安全顾虑是律所不付费的第一障碍，必须优先解决"},{"step":"核心功能","decision":"P0只做登记+分配+追踪+提醒四件事","reason":"小律所核心痛点明确，不过度设计，快速交付可用产品"},{"step":"定价","decision":"199元/月起步","reason":"律师行业客单价高，199元相当于一个小时的咨询费，付费门槛不高"},{"step":"推广渠道","decision":"律师协会和法律培训机构合作","reason":"律师圈子封闭，通过行业渠道比广告投放效率高得多"},{"step":"私有化","decision":"提供私有化部署选项","reason":"部分律所有数据不出境的合规要求，私有化是打消顾虑的关键选项"}]',
'submitted', 36, NOW() - INTERVAL '33 days', NOW() - INTERVAL '34 days', NOW() - INTERVAL '33 days'),

(8, 7, E'# 律刻 - 律所咨询与案件全周期管理平台\n\n## 1. 产品概述\n\n律刻（LawTick）是一款专为 3-8 人中小律师事务所设计的轻量级数字化管理工具，以「不改变律师工作习惯，只帮他们记得更好」为核心设计原则。产品通过微信小程序 + Web 双端，实现来访咨询结构化登记、智能案件分配、多维度进度追踪和关键节点自动提醒，帮助小律所将因管理疏漏导致的客户流失率从行业平均的 15% 降低至 3% 以内。\n\n**独特价值**：律刻不是律师学法律的工具，也不是律所的 ERP——它是律所的「记忆助手」，让每个律师和前台都能做到「零遗漏」。\n\n## 2. 市场分析\n\n| 市场维度 | 关键数字 | 含义 |\n|---------|---------|------|\n| 全国律所数量 | 38,000 家 | 市场规模基础 |\n| 3-8 人小律所 | 约 25,000 家 | 目标市场 |\n| 小律所每年新增数量 | 约 2,000 家 | 市场持续扩大 |\n| 律师总人数 | 约 65 万人（2023）| 年增约 10% |\n| 法律服务市场规模 | 约 2,600 亿元 | 全国总盘 |\n| 小律所 IT 预算 | 平均 <¥12,000/年 | 预算有限，需轻量工具 |\n| 因管理问题流失客户的律所 | >60% | 巨大痛点 |\n\n**市场增量来源**：\n1. 新设立律所（年均 2,000 家）直接进入数字化\n2. 已有律所从纸质/微信迁移（更大的市场，但有迁移成本）\n3. 律所规模升级（小所变中所，需要更完整的管理）\n\n## 3. 竞品矩阵\n\n| 竞品名称 | 核心卖点 | 适合律所规模 | 价格（月）| 核心局限性 |\n|---------|---------|------------|---------|----------|\n| 律驰 | 律所 OA 系统 | 中大律所（50+人）| ¥500+ | 功能过于复杂，实施成本高 |\n| 管理大师（法律版）| 案件管理 | 中型律所 | ¥300+ | 界面老旧，移动端体验差 |\n| 钉钉 + 自定义 | 通用协作 | 全规模 | ¥0-30/人 | 需要大量自定义，非开箱即用 |\n| Clio（国际）| 律所管理 | 中小律所 | $49/人 | 无中文、无本土化 |\n| 自建微信群 + 纸质 | 传统方式 | 小律所 | 免费 | 信息散乱，无法追踪 |\n| **律刻** | **小所专属轻量** | **3-8 人小律所** | **¥199** | **新品牌** |\n\n## 4. 目标用户画像\n\n### 画像 A：「事务管理者」合伙律师 - 王德明\n- **基本信息**：45 岁，北京，执业 18 年，律所管理合伙人\n- **律所规模**：5 名律师 + 2 名助理 + 1 名前台\n- **当前管理方式**：微信群通知 + Excel 案件台账 + 每周例会\n- **核心痛点**：\n  1. Excel 台账各律师更新不及时，数据不准确\n  2. 重要诉讼节点（开庭/答辩/上诉期）没有系统提醒，全靠人工\n  3. 不知道每个律师手上现在有多少案子、哪些在关键节点\n- **期望**：「像看一块仪表盘一样看到所有案件状态」\n- **付费决策权**：有，399 元/月以内可以自己决定\n\n### 画像 B：「实干型」执行律师 - 林佳\n- **年龄**：29 岁，入职 4 年的执业律师，专注民商事诉讼\n- **日常困境**：\n  1. 同时管理 15-20 个案件，每个案件有不同的节点\n  2. 开庭日期靠 iPhone 日历提醒，但无法与案件信息关联\n  3. 出差时客户打电话来询问进展，只能靠记忆回答，容易出错\n- **核心需求**：随时随地查看任意案件的完整信息和进度\n- **对工具的期待**：「就像我自己的副驾驶，帮我记住所有事」\n\n### 画像 C：「高效前台」行政助理 - 陈曦\n- **年龄**：23 岁，律所前台兼行政，负责接待和登记\n- **工作量**：每天接待 8-15 名来访或电话咨询客户\n- **现状困境**：用 A4 纸记录，写完放在律师桌上，经常被压在文件下面找不到\n- **核心需求**：\n  1. 快速录入客户信息（尽量不打字，用选择代替输入）\n  2. 录完能立即通知对应律师\n  3. 案件进展能查到，客户来电时能回答\n- **使用设备**：电脑 + 手机两端都用\n\n## 5. 核心功能设计\n\n### P0 - MVP（8 周）\n\n| 功能 | 用户价值 | 设计要点 |\n|------|---------|--------|\n| 结构化咨询登记 | 取代纸质，标准化信息录入 | 预置法律事务类型标签，减少打字 |\n| 律师智能推荐分配 | 按专长和当前工作量推荐 | 显示每位律师当前案件数，人工确认 |\n| 案件全周期看板 | 全所案件一目了然 | 按状态分列（咨询/签约/进行中/结案）|\n| 节点提醒 | 关键法律节点自动提醒 | 律师设置节点，系统在 D-3/D-1 自动提醒 |\n\n### P1 - 一期（第 3-4 个月）\n\n| 功能 | 价值 | 技术要点 |\n|------|------|--------|\n| 客户档案卡 | 历史案件一键查看 | 按手机号关联所有历史咨询 |\n| 案件文件夹 | 相关文件集中存储 | OSS 存储，支持 PDF/Word/图片 |\n| 工作量统计 | 律师绩效参考 | 案件数/咨询量/结案量按周/月统计 |\n| 客户跟进日志 | 每次沟通记录 | 时间线展示，支持附件 |\n\n### P2 - 二期\n\n| 功能 | 描述 |\n|------|------|\n| 客户自助进度查询 H5 | 发给客户的进度查询链接 |\n| 委托合同模板生成 | 内置合同模板，自动填充客户信息 |\n| 费用记录和催收 | 律师费记录，未结清自动提醒 |\n| 数据导出 | Excel/PDF 格式导出备份 |\n\n## 6. 技术架构\n\n```\n架构原则：数据安全 + 高可用 + 渐进扩展\n\n客户端：\n  - PC Web 管理端：React 18 + Ant Design（前台+律师 PC 使用）\n  - 微信小程序：律师外出查看/操作\n\n服务端：\n  - 主 API：Go + Echo v4（RESTful）\n  - 通知服务：企业微信机器人 + 阿里云短信\n  - 文件处理：阿里云 OSS + 防盗链\n  - 定时任务：Go cron（节点提醒，每日 8:00 扫描）\n\n数据层：\n  - PostgreSQL 16（主数据，支持 JSONB 存储灵活字段）\n  - Redis 7（会话 + 热点缓存）\n\n安全体系：\n  - 传输加密：全站 HTTPS/TLS 1.3\n  - 存储加密：数据库字段级 AES-256 加密\n  - 访问控制：RBAC（合伙人/律师/助理/前台四种角色）\n  - 审计日志：所有数据操作完整记录\n  - 合规：申请等保二级认证\n```\n\n## 7. 商业模式\n\n| 版本 | 月价 | 人数上限 | 核心权益 |\n|------|------|---------|--------|\n| 基础版 | ¥199/月 | ≤5 人 | 登记+分配+看板+提醒 |\n| 专业版 | ¥349/月 | ≤10 人 | 基础+文件+统计+客户档案 |\n| 旗舰版 | ¥599/月 | 无上限 | 专业+合同模板+费用管理 |\n| 私有化 | ¥18,000（一次性）| 无上限 | 全功能，本地服务器部署 |\n\n**预估营收路径**：\n- 第 6 个月：50 付费律所，MRR 约 1.5 万\n- 第 12 个月：200 付费律所，MRR 约 6 万\n- 第 24 个月：800 付费律所，MRR 约 25 万\n\n## 8. MVP 路线图\n\n| 月份 | 阶段 | 关键产出 | 成功标准 |\n|------|------|---------|--------|\n| 第 1 月 | 调研 | 访谈 20 家小律所，验证需求 | 需求文档冻结 |\n| 第 2-3 月 | 开发 | P0 功能完成 + 安全体系 | 内测可用 |\n| 第 4 月 | 内测 | 10 家律所内测 | NPS ≥35 |\n| 第 5-6 月 | 公测 | 律师协会渠道推广 | 注册律所 100，付费 30 |\n\n## 9. 成功指标\n\n| 指标 | 目标（6 个月）|\n|------|-------------|\n| 注册律所数 | ≥150 |\n| 付费律所数 | ≥40 |\n| MRR | ¥10,000 |\n| 案件登记条数 | >5,000 |\n| NPS | ≥45 |\n| 月续费率 | ≥92% |\n\n## 10. 风险与应对\n\n| 风险 | 等级 | 应对 |\n|------|------|------|\n| 数据安全顾虑，律所不敢上云 | 极高 | 等保二级 + 私有化部署选项 + 加密白皮书 |\n| 律师使用意愿低（习惯旧方式）| 高 | 前台登记替代律师操作，降低律师负担 |\n| 律所规模小，获客分散 | 中 | 律师协会/培训机构批量合作 |\n| 竞品专门针对小所推出低价版 | 中 | 快速占领市场+建立口碑壁垒 |\n| 法律法规变化（数据处理）| 中 | 持续跟进数据合规要求，灵活应对 |',
'[{"step":"命名","decision":"命名律刻LawTick","reason":"法律+时间两重含义，英文名便于品牌化，体现准时提醒的核心价值"},{"step":"核心设计原则","decision":"不改变工作习惯，只帮记得更好","reason":"律师群体习惯固化，强迫改变会遭到抵制，渐进式融入是最低摩擦路径"},{"step":"角色权限","decision":"设计合伙人/律师/助理/前台四种角色","reason":"律所有严格的层级和权限需求，RBAC是小律所管理工具的基础设施"},{"step":"安全优先","decision":"第一版就做等保二级+字段加密","reason":"律所客户数据极度敏感，安全不过关是一票否决，必须优先解决"},{"step":"获客渠道","decision":"律师协会+法律培训机构是核心渠道","reason":"律所圈子封闭，行业背书比广告有效10倍"},{"step":"私有化","decision":"提供私有化部署选项","reason":"部分律所合规要求数据不出境，这是打消顾虑的关键差异化选项"}]',
'submitted', 29, NOW() - INTERVAL '27 days', NOW() - INTERVAL '28 days', NOW() - INTERVAL '27 days'),

(8, 14, E'# 案件管家 - 小律所一站式业务管理系统\n\n## 1. 产品概述\n\n案件管家是专为 3-8 人规模中小律师事务所设计的业务管理 SaaS，产品从「如何让小律所今天就能用上数字化管理」这一务实出发点设计。不同于市面上功能庞杂的律所 OA 系统，案件管家遵循「极简上手，专注核心」原则，律所注册即用，无需培训，前台可在 5 分钟内掌握全部操作。\n\n**核心三板斧**：\n1. **一张登记表**：来访咨询结构化登记，取代纸条和备忘录\n2. **一块看板**：全所案件实时状态可视化，合伙人一目了然\n3. **一套提醒**：关键节点自动提醒，再也不会因为忘记节点出差错\n\n**目标**：成为「全国 25,000 家小律所的默认管理工具」。\n\n## 2. 市场分析\n\n| 分析维度 | 数据 | 战略意义 |\n|---------|------|--------|\n| 目标市场规模（3-8 人律所）| 25,000 家 | 足够大的市场 |\n| 年新增小律所 | 约 2,000 家 | 自然增量 |\n| 律师年增长率 | 约 10% | 行业持续扩张 |\n| 当前 SaaS 工具渗透率 | <5% | 蓝海市场 |\n| 平均每所年 IT 支出意愿 | ¥5,000-15,000 | 支付能力 OK |\n| 因管理疏漏导致年损失 | 约 5-20 万（律所）| 痛点够大 |\n| 律所主要获客渠道 | 转介绍（占 70%）| 服务质量是关键 |\n\n**关键洞察**：律所最大的隐性成本是「因管理失误导致的客户口碑损伤」。一次因遗忘跟进而失去的客户，远比 200 元/月的工具订阅费用高。这是产品销售的核心说辞。\n\n## 3. 竞品矩阵\n\n| 竞品 | 核心功能 | 小所体验 | 价格/月 | 数据安全 | 移动端 |\n|------|---------|---------|--------|---------|-------|\n| 律驰 | 全功能律所管理 | 差（太复杂）| ¥500+ | 云端 | 有（慢）|\n| 法务云 | 案件+合同管理 | 中 | ¥300+ | 云端 | 有 |\n| 钉钉审批流 | 通用流程管理 | 中（需配置）| ¥0-30/人 | 云端 | 好 |\n| 自建 Excel | 案件台账 | 好（熟悉）| 免费 | 本地 | 无 |\n| **案件管家** | **小所专属核心**| **优（极简）**| **¥199** | **加密云** | **优** |\n\n**竞争策略**：不与大律所 OA 系统正面竞争，专注「25,000 家小律所」这个被大厂忽视的细分市场，以极简体验和专属功能建立壁垒。\n\n## 4. 目标用户画像\n\n### 画像 A：「创业期」新律所合伙人 - 李绍华\n- **基本信息**：34 岁，在大律所做了 8 年后自己开所，律所成立 1 年\n- **律所现状**：4 名律师 + 1 名行政，月均新案 30 件\n- **当前管理方式**：Google 表格（自己设计的）+ 微信群\n- **核心痛点**：\n  1. Google 表格维护麻烦，每次开会前要手动汇总\n  2. 新员工加入时，需要花时间教他们用表格\n  3. 客户数据在表格里，外出时手机打开很麻烦\n- **对产品期望**：「和我现在用的表格差不多，但是手机上也好用，而且有自动提醒」\n- **付费决策**：每月 200-300 元没问题\n\n### 画像 B：「稳定期」中年合伙人 - 郑国庆\n- **基本信息**：52 岁，律所运营 10 年，6 名律师，偏保守\n- **现状**：一直用纸质登记本 + 前台管理\n- **对数字化的态度**：担心「学不会」「数据不安全」「出问题谁负责」\n- **说服策略**：\n  1. 免费试用 30 天，不满意全额退款\n  2. 数据随时可以导出，不锁定\n  3. 提供 1v1 上门配置服务\n- **付费意愿**：如果真的好用，300 元/月可以接受\n\n### 画像 C：「专业型」专项律师助理 - 冯磊\n- **年龄**：27 岁，律所唯一行政，管所有行政事务\n- **每天工作**：接待咨询 → 安排律师 → 跟进进度 → 提醒节点 → 协助签约\n- **核心需求**：\n  - 一个系统管理所有事项，不用在微信、纸条、Excel 之间切换\n  - 系统能自动提醒，减少人工追踪\n  - 出差时律师也能查看案件信息\n\n## 5. 核心功能设计\n\n### P0 - 核心 MVP（6 周交付）\n\n| 功能 | 具体描述 | 极简原则 |\n|------|---------|--------|\n| 来访/电话咨询登记 | 姓名+手机+案件类型+简述+负责律师，5 个核心字段 | 字段最少化，1 分钟完成登记 |\n| 案件分配通知 | 登记完成后，系统自动向指定律师发微信/短信通知 | 无需律师主动查看 |\n| 案件状态看板 | Kanban 风格：咨询/评估/签约/进行/结案 | 可拖拽更新状态 |\n| 关键节点提醒 | 律师设定节点日期，系统 D-3 和 D-1 自动提醒 | 预置常见法律节点（开庭/答辩等）|\n\n### P1 - 一期功能（上线后 2 个月）\n\n| 功能 | 价值 | 实现方案 |\n|------|------|--------|\n| 客户 360 档案 | 历史案件一键查到 | 按手机号聚合所有历史记录 |\n| 律师工作量看板 | 合伙人了解团队工作量 | 按律师统计各阶段案件数 |\n| 文件附件管理 | 案件文件集中管理 | 每个案件可上传 ≤20 个文件 |\n| 月度报表导出 | 案件统计 Excel 导出 | 兼容律所现有台账格式 |\n\n### P2 - 二期（3-6 个月后）\n\n| 功能 | 战略价值 |\n|------|--------|\n| 客户进度查询 H5 | 提升客户体验，减少催问电话 |\n| 委托合同一键生成 | 提升效率，减少人工填表 |\n| 律师费催收模块 | 解决律所收款难的痛点 |\n| 跨所协作（联合代理）| 多律所协作案件管理 |\n\n## 6. 技术架构\n\n```\n架构设计：简单、稳定、安全优先\n\n前端：\n  - PC Web：Vue 3 + Ant Design Vue（主要使用场景）\n  - 微信小程序：律师移动端查看（功能子集）\n\n后端：\n  - API：Go + Echo v4\n  - 通知引擎：Go Worker（企业微信机器人+短信）\n  - 定时服务：Go cron（每日 8:00 扫描待提醒节点）\n\n存储：\n  - PostgreSQL 16（主数据库）\n  - Redis 7（缓存+会话）\n  - 阿里云 OSS（文件存储，服务端加密）\n\n安全措施（律所核心关切）：\n  - 等保二级认证（首年完成）\n  - 敏感字段 AES-256 加密\n  - 完整操作审计日志\n  - 多租户严格隔离\n  - 支持数据本地备份下载\n```\n\n## 7. 商业模式\n\n| 方案 | 定价 | 功能范围 | 目标用户 |\n|------|------|---------|--------|\n| 试用版 | 免费 30 天 | 全功能 | 新注册律所 |\n| 基础版 | ¥199/月 | P0+P1 核心功能，≤5 人 | 3-5 人所 |\n| 标准版 | ¥349/月 | 全 P1 功能，≤10 人 | 5-8 人所 |\n| 高级版 | ¥599/月 | 全功能+优先支持 | 8-15 人所 |\n| 私有部署 | ¥20,000（一次性）| 全功能，本地服务器 | 合规敏感律所 |\n\n## 8. MVP 路线图\n\n| 时间 | 里程碑 | 目标 |\n|------|-------|------|\n| 第 1 月 | 调研期 | 访谈 25 家律所，确认核心功能列表 |\n| 第 2-3 月 | MVP 开发 | P0 功能 + 安全体系 |\n| 第 4 月 | 封闭内测 | 10 家律所内测，收集反馈 |\n| 第 5 月 | 公测上线 | 律师协会渠道推广 |\n| 第 6 月 | 商业化 | 付费转化，P1 功能上线 |\n\n## 9. 成功指标\n\n| 维度 | 指标 | 6 个月目标 |\n|------|------|----------|\n| 规模 | 注册律所 | ≥200 |\n| 活跃 | 月活律所（有案件录入）| ≥140 |\n| 商业 | 付费律所 | ≥50 |\n| 商业 | MRR | ¥12,000 |\n| 质量 | 月续费率 | ≥92% |\n| 口碑 | NPS | ≥48 |\n\n## 10. 风险与应对\n\n| 风险 | 可能性 | 影响 | 应对策略 |\n|------|-------|------|--------|\n| 数据安全顾虑导致不上云 | 高 | 高 | 等保认证+私有化选项+数据随时导出承诺 |\n| 律师不愿改变工作习惯 | 高 | 高 | 让前台作为主要用户，律师只需被动接收通知和查看 |\n| 小律所获客分散，CAC 高 | 中 | 中 | 律师协会批量合作，内容营销降低 CAC |\n| 竞品价格战 | 中 | 中 | 通过功能专属性和数据积累建立壁垒 |\n| 合规风险（处理客户敏感信息）| 中 | 高 | 律所是数据控制者，明确合同条款 |',
'[{"step":"设计原则","decision":"极简上手，5分钟可用","reason":"律所没有IT部门，产品必须开箱即用，否则即使注册了也不会用"},{"step":"MVP边界","decision":"只做三板斧：一张表+一块板+一套提醒","reason":"这三件事解决了小律所90%的管理痛点，其他都是锦上添花"},{"step":"用户策略","decision":"让前台成为主要用户","reason":"律师抵触改变，但前台是管理的执行者，以前台为切入点降低推广阻力"},{"step":"安全","decision":"30天免费+数据随时导出+等保认证","reason":"降低试用门槛，打消数据锁定顾虑，等保认证是信任背书"},{"step":"定价","decision":"从199元/月开始","reason":"律师费一小时就能覆盖月费，ROI极高，付费门槛不是障碍"},{"step":"增长","decision":"律师协会是核心推广渠道","reason":"律所圈子封闭，协会背书是最快建立信任的方式"}]',
'submitted', 41, NOW() - INTERVAL '21 days', NOW() - INTERVAL '22 days', NOW() - INTERVAL '21 days'),

(8, 21, E'# 诉管云 - 律所数字化管理一站式解决方案\n\n## 1. 产品概述\n\n诉管云是针对 3-8 人小型律师事务所的轻量级 SaaS 管理平台，以「让每个律师事务所都能运营得像一个专业服务机构」为产品愿景。产品通过来访登记、案件分配、进度追踪、节点提醒、费用管理五大核心模块，帮助小律所实现从「靠人力记忆维系」到「依靠系统驱动管理」的数字化升级。\n\n**核心差异化**：诉管云是市场上唯一同时满足「小律所 IT 预算有限（<¥500/月）」「数据安全合规」「开箱即用（无需培训）」「移动端友好」四大约束的法律行业 SaaS 产品。\n\n## 2. 市场分析\n\n| 市场指标 | 数据 | 说明 |\n|---------|------|------|\n| 全国律所总数 | 38,000 家 | 司法部 2023 年年报 |\n| 10 人以下小律所 | 约 28,000 家 | 占比 74% |\n| 3-8 人目标律所 | 约 22,000 家 | 核心目标市场 |\n| 当前数字化工具渗透率 | <8% | 极低，机会大 |\n| 法律服务年均增速 | 约 12% | 国家统计局数据 |\n| 年均因管理问题流失客户 | 约 20% | 律所调研估算 |\n| 律师年均工作案件量 | 约 50-150 件 | 节点管理需求强 |\n\n**竞争空白分析**：法律行业 SaaS 存在明显的「中间断层」——要么是面向大律所（100人+）的重型 OA 系统（价格贵、实施周期长），要么是免费的通用协作工具（无法律专属功能）。3-8 人小律所的专属工具存在明显市场空白。\n\n## 3. 竞品矩阵\n\n| 竞品 | 定位 | 价格 | 小所友好 | 法律专属 | 移动端 | 数据安全 |\n|------|------|------|---------|---------|-------|--------|\n| 律驰 | 大律所 OA | ¥500+/月 | 差 | 高 | 有 | 高 |\n| Clio（国际）| 中小律所 | $49/人/月 | 中 | 高 | 优 | 高 |\n| 钉钉 | 通用企业 | ¥0-30/人 | 好 | 无 | 优 | 中 |\n| 飞书 | 通用企业 | ¥0-30/人 | 好 | 无 | 优 | 中 |\n| Excel 自建 | 无软件 | 免费 | 好 | 低 | 差 | 低 |\n| **诉管云** | **小所专属** | **¥199-599/月** | **极好** | **高** | **优** | **高** |\n\n## 4. 目标用户画像\n\n### 画像 A：「快速成长」新律所 - 方晓军律师\n- **基本信息**：36 岁，律所成立 2 年，5 人团队，主营公司业务\n- **月均新案件量**：35-45 件\n- **痛点三角**：\n  1. 案件分配靠口头，常常各律师不清楚谁负责哪个案子\n  2. 没有系统的节点管理，靠律师个人日历，出过两次漏掉答辩期的险情\n  3. 月底对账收款时，总有几个案件的费用不清楚\n- **期望**：「我需要一个专门给律所用的管理软件，不要那种大公司 OA 那么复杂的」\n- **决策方式**：主动搜索、对比后决策，注重性价比\n\n### 画像 B：「经验丰富」传统律师 - 孙老师\n- **年龄**：58 岁，执业 25 年，律所创始人\n- **数字化态度**：不反对，但不懂，担心数据泄露\n- **日常管理**：有一本厚厚的手账，记录所有案件\n- **说服路径**：\n  1. 数据安全认证（等保/ISO）\n  2. 纸质手账的数字化平行替代（保留手账习惯，系统作为备份）\n  3. 前台主要操作，他只需要在手机上查看\n- **付费决策**：需要律所里年轻律师的推荐\n\n### 画像 C：「数字原生」年轻律师 - 许晓彤\n- **年龄**：25 岁，律所第 1 年，专注互联网法务\n- **数字化态度**：强烈主张数字化管理，但没有决策权\n- **角色**：内部倡导者（产品推广的关键中间人）\n- **核心需求**：移动端流畅、界面现代、有 API 接口可以和其他工具集成\n- **影响力**：她是推动律所购买工具的主要内部力量\n\n## 5. 核心功能设计\n\n### P0 - MVP（7 周）\n\n| 功能 | 核心场景 | 关键指标 |\n|------|---------|--------|\n| 来访咨询快速登记 | 前台 1 分钟完成客户信息录入 | 平均登记时间 <90 秒 |\n| 案件分配系统 | 一键分配+即时通知律师 | 通知送达 <10 秒 |\n| 案件全状态看板 | 合伙人看全所案件实时状态 | 页面加载 <1 秒 |\n| 节点日历 + 自动提醒 | 关键法律节点（开庭/答辩/期限）提前提醒 | 提醒准时率 >99% |\n\n### P1 - 一期扩展（第 3-4 月）\n\n| 功能 | 业务价值 | 实现要点 |\n|------|---------|--------|\n| 客户完整档案 | 同一客户多次委托，历史完整可查 | 手机号唯一标识，历史关联 |\n| 律师工作量分析 | 合伙人了解团队负载，优化分配 | 可视化图表，周/月/年维度 |\n| 案件附件管理 | 合同/证据/文书集中存储 | 单文件 ≤50MB，总存储按版本限制 |\n| 跟进日志时间线 | 每次客户沟通记录，可追溯 | 时间顺序，支持附件 |\n\n### P2 - 后续规划\n\n| 功能 | 目标 | 技术方案 |\n|------|------|--------|\n| 客户自助进度查询 | 减少客户催问电话 | 发给客户专属 H5 链接 |\n| 委托合同智能生成 | 提升效率，减少手工填表 | 内置 10+ 种合同模板 |\n| 律师费管理+催收 | 解决收款难 | 记账+智能催收提醒 |\n| 数据 API 接口 | 与外部工具集成（许晓彤诉求）| REST API + Webhook |\n\n## 6. 技术架构\n\n```\n设计优先级：安全 > 稳定 > 性能 > 功能\n\n前端：\n  - PC Web：React 18 + Ant Design（主操作端）\n  - 微信小程序：律师/合伙人移动查看（只读+简单操作）\n\n服务端：\n  - RESTful API：Go + Echo v4\n  - 异步任务：Go + Redis Queue（通知发送）\n  - 节点提醒：Cron + PostgreSQL 定时扫描\n\n数据安全体系：\n  - 网络层：Cloudflare WAF + HTTPS\n  - 应用层：JWT 认证 + RBAC 权限（合伙人/律师/助理/前台）\n  - 数据层：PostgreSQL 字段级加密（AES-256）+ 多租户隔离\n  - 审计：所有增删改操作完整日志\n  - 备份：每日异地备份，保留 30 天\n  - 合规：等保二级认证（上线后 6 个月完成）\n\n存储：\n  - PostgreSQL 16\n  - Redis 7\n  - 阿里云 OSS（文件，服务端加密）\n```\n\n## 7. 商业模式\n\n| 版本 | 定价 | 权限 | 目标 |\n|------|------|------|------|\n| 免费试用 | 30 天全功能 | 无限制 | 降低试用门槛 |\n| 基础版 | ¥199/月 或 ¥1,990/年 | ≤5 人，P0+P1 | 3-5 人所 |\n| 标准版 | ¥399/月 或 ¥3,990/年 | ≤10 人，全功能 | 5-10 人所 |\n| 专业版 | ¥699/月 | 无限制+API 接口 | 技术能力强的所 |\n| 私有化 | ¥25,000 一次性 | 全功能，本地部署 | 合规要求高的所 |\n\n## 8. MVP 路线图\n\n| 阶段 | 周期 | 目标 | 验收 |\n|------|------|------|------|\n| 调研 | 第 1-4 周 | 访谈 25 家律所，线框图评审 | PRD 冻结 |\n| 开发 | 第 5-11 周 | P0 功能 + 安全体系 | 内测可用 |\n| 内测 | 第 12-16 周 | 10 家律所内测 | NPS ≥40 |\n| 公测 | 第 17-20 周 | 律师协会渠道推广 | 注册 150 所 |\n| 商业化 | 第 21-24 周 | 付费转化 + P1 上线 | 付费 50 所 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 | 12 个月目标 |\n|------|----------|----------|\n| 注册律所 | 250 | 800 |\n| 付费律所 | 55 | 250 |\n| MRR | ¥14,000 | ¥60,000 |\n| 月续费率 | ≥92% | ≥94% |\n| NPS | ≥45 | ≥55 |\n| 案件登记量 | >8,000 | >50,000 |\n\n## 10. 风险与应对\n\n| 风险 | 级别 | 应对 |\n|------|------|------|\n| 数据安全顾虑 | P0 级 | 等保认证 + 加密白皮书 + 私有化选项 + 数据随时可导出 |\n| 律师学习成本 | P1 级 | 前台是主用户，律师被动接收通知，降低使用负担 |\n| 小所分散，获客难 | P1 级 | 律师协会/培训机构合作，口碑裂变激励 |\n| 功能蔓延，MVP 超期 | P2 级 | 严格 P0 边界，其他需求进 backlog |\n| 竞品跟进 | P2 级 | 法律行业专属数据（节点库/合同模板）是护城河 |',
'[{"step":"市场定位","decision":"聚焦3-8人律所，不做大所市场","reason":"大所市场有成熟竞品，小所市场空白明显，差异化竞争策略"},{"step":"核心差异","decision":"四大约束同时满足：预算/安全/易用/移动","reason":"现有产品都无法同时满足这四点，这是小律所真实的购买决策框架"},{"step":"安全体系","decision":"安全是P0级别，与核心功能同步开发","reason":"律所数据泄露是致命问题，安全顾虑是购买转化的最大障碍"},{"step":"推广策略","decision":"发现内部倡导者（年轻律师）是关键","reason":"传统律师有决策权但缺乏数字化驱动力，年轻律师有动力但没有决策权，需要双向配合"},{"step":"定价","decision":"30天全功能免费试用","reason":"降低试用门槛，让律所充分体验产品价值，再做付费决策"},{"step":"技术架构","decision":"安全>稳定>性能>功能的优先级","reason":"律所用户最在意的不是功能多少，而是数据不丢、系统稳定、安全可信"}]',
'submitted', 32, NOW() - INTERVAL '16 days', NOW() - INTERVAL '17 days', NOW() - INTERVAL '16 days');

-- ============================================================
-- IDEA 9: 农家乐订房管理 - Author 4
-- ============================================================
INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(9, 4, E'# 农乐订 - 农家乐/乡村民宿一站式订房管理工具\n\n## 1. 产品概述\n\n农乐订是专为 10-30 间房规模的乡村民宿和农家乐设计的轻量级预订管理 SaaS，核心解决「靠微信和电话管理预订，旺季重复预订多、退改混乱、沟通效率低」三大痛点。产品通过智能房态日历、客户自助预订链接和自动化退改规则，帮助民宿主将旺季人工管理时间减少 60%，同时提升客户预订体验和复购率。\n\n**产品定位**：不是 OTA 平台（美团/途家），而是民宿主的「自营私域预订管理后台」，帮助民宿主把自己的老客户和自然流量管理好，减少对平台的依赖。\n\n**背景**：2023 年乡村旅游人次突破 25 亿次，农家乐和乡村民宿数量超过 180 万家，但 95% 以上仍用微信和纸质方式管理预订，数字化程度极低。\n\n## 2. 市场分析\n\n| 市场指标 | 数据 | 来源/说明 |\n|---------|------|----------|\n| 乡村旅游年人次 | 25 亿次（2023）| 文化和旅游部 |\n| 农家乐/乡村民宿数量 | 180 万家 | 估算（含各类规模）|\n| 10-30 间房目标民宿 | 约 35 万家 | 中等规模，有付费意愿 |\n| 旺季入住率 | 90-100%（节假日）| 管理压力大 |\n| 淡季入住率 | 20-40% | 需要营销工具 |\n| 民宿主 SaaS 使用率 | <5% | 机会窗口大 |\n| 民宿平均年收入 | 30-150 万元 | 有付费能力 |\n| 愿意付费解决管理问题 | 65%（N=40）| 问卷调研 |\n\n**旺季核心矛盾**：五一、国庆、暑假期间，一家 20 间房的农家乐可能同时收到 100+ 个询问，靠微信回复根本来不及，导致漏单和重复预订问题频发。\n\n## 3. 竞品矩阵\n\n| 产品 | 定位 | 月费 | 适合农家乐 | 自营预订 | 退改管理 | 综合评分 |\n|------|------|------|----------|---------|---------|--------|\n| 途家 PMS | OTA 民宿管理 | 抽佣 | 中 | 弱（依赖平台）| 有 | 5/10 |\n| 美团民宿后台 | 平台工具 | 抽佣 | 高 | 弱（平台内）| 有 | 6/10 |\n| 客栈管家 | 客栈管理 | ¥198+ | 高 | 有 | 有 | 7/10 |\n| 酒店管家 APP | 通用酒店 | ¥299+ | 低（偏酒店）| 有 | 有 | 5/10 |\n| 微信+纸质表格 | 无工具 | 免费 | 高（习惯）| 手动 | 手动 | 3/10 |\n| **农乐订** | **农家乐专属** | **¥99** | **极高** | **✅** | **✅** | **9/10** |\n\n**差异化关键**：客栈管家是最接近竞品的，但其价格较高且定位更偏向精品民宿（有 PMS 功能、连接 OTA 等），而农乐订专注于「自营私域预订管理」这一更轻量的场景。\n\n## 4. 目标用户画像\n\n### 画像 A：「农家乐老板」王大叔\n- **基本信息**：52 岁，贵州黔东南，农家乐 18 间房，自家经营\n- **现状**：全靠微信接单，每逢节假日手机被打爆，有 2-3 次重复预订\n- **技术水平**：会微信，不会用 App，不用电脑\n- **核心需求**：\n  1. 手机就能看有哪些房间空着、哪些已预订\n  2. 客户发来「有房吗」不用一个个回，自己去看链接\n  3. 客人取消的时候自动更新，不用手动改\n- **付费意愿**：如果旺季不再出错，100 元/月完全值\n- **关键特征**：需要「手机能用」「一看就懂」\n\n### 画像 B：「精品民宿主理人」林晓琳\n- **年龄**：34 岁，浙江莫干山，精品民宿 15 间房\n- **现状**：在途家和小红书上运营，有自己的私域微信群\n- **核心需求**：\n  1. 私域客户可以直接在自己的小程序下单，不走平台（省佣金）\n  2. 多个平台的房态可以统一管理（途家+自营）\n  3. 旺季复购客户专属优惠自动发送\n- **付费意愿**：¥198/月，省下平台抽佣就能回本\n- **关键特征**：数字化能力强，对工具有要求\n\n### 画像 C：「连锁农家乐」经营者 - 周总\n- **年龄**：45 岁，管理 3 家农家乐（共 65 间房）\n- **核心痛点**：3 家店分开管，员工各管各的，总部不知道实时状态\n- **需求**：统一看板，一个后台管 3 家店\n- **付费意愿**：每家 ¥99，3 家 ¥297/月，或者有优惠的多店版\n\n## 5. 核心功能设计\n\n### P0 - MVP（6 周）\n\n| 功能 | 用户价值 | 设计要点 |\n|------|---------|--------|\n| 房态日历 | 直观看到所有房间的预订/空闲状态 | 色块区分（绿=空闲/红=已订/黄=待确认），手机触控优化 |\n| 自助预订链接 | 客户自己查房态和预订，减少微信询问 | H5 页面，无需安装，填写手机/日期/人数即可 |\n| 预订确认提醒 | 新预订时自动通知民宿主 | 微信服务通知+短信双通道 |\n| 退改规则设置 | 民宿主设置取消政策，客户自助操作 | 支持提前 X 天免费取消，否则扣押金 |\n\n### P1 - 一期（第 3-4 个月）\n\n| 功能 | 核心价值 | 优先级理由 |\n|------|---------|----------|\n| 旺季排期管理 | 按节假日设置最短入住天数/禁止特殊日期入住 | 节假日管理是最高频需求 |\n| 客户档案 | 老客户记录（偏好、历史入住、备注）| 提升复购和服务质量 |\n| 自动欢迎消息 | 预订确认后自动发送民宿位置+注意事项 | 减少入住前问问题 |\n| 押金管理 | 记录押金收取和退还状态 | 高频纠纷点 |\n\n### P2 - 后续功能\n\n| 功能 | 描述 |\n|------|------|\n| OTA 房态同步 | 与途家/美团双向同步，避免跨平台重复预订 |\n| 复购营销 | 老客户旺季前自动发送优惠/提前预订提醒 |\n| 评价管理 | 收集客户评价，提醒好评分享 |\n| 多店统一管理 | 连锁农家乐统一看板 |\n\n## 6. 技术架构\n\n```\n架构原则：手机优先，农村网络条件下可用\n\n前端：\n  - 民宿主管理端：微信小程序（主）+ 响应式 H5（辅）\n  - 客户预订端：H5 网页（无需安装任何 App）\n\n后端：\n  - API：Go + Echo v4\n  - 通知服务：微信服务通知 + 短信\n  - 定时任务：Go cron（旺季提醒、押金到期提醒）\n\n基础设施（针对农村网络优化）：\n  - CDN 全国加速（Cloudflare）\n  - 图片压缩（农村 4G 网络，页面需轻量）\n  - 离线缓存（PWA，断网时也能查看缓存的房态）\n\n存储：\n  - PostgreSQL 16\n  - Redis（会话+缓存）\n  - 阿里云 OSS（民宿图片）\n```\n\n**农村网络特别考量**：部分农家乐位于山区，4G 信号不稳定。前端需要做离线缓存和轻量化优化，确保弱网下仍能基本使用。\n\n## 7. 商业模式\n\n| 版本 | 定价 | 房间数上限 | 核心权益 |\n|------|------|----------|--------|\n| 免费版 | ¥0/月 | ≤10 间 | 基础房态日历+预订链接 |\n| 标准版 | ¥99/月 | ≤30 间 | 全 P0+P1 功能 |\n| 专业版 | ¥199/月 | ≤60 间 | 全功能+OTA 同步+数据报表 |\n| 多店版 | ¥79/家（≥3 家）| 不限 | 标准版权益+统一看板 |\n\n## 8. MVP 路线图\n\n| 时间 | 阶段 | 关键任务 | 成功标准 |\n|------|------|---------|--------|\n| 第 1 月 | 调研 | 访谈 20 家农家乐，原型设计 | 核心功能 PRD 锁定 |\n| 第 2-3 月 | 开发 | P0 功能 + 微信小程序 | 内测可用 |\n| 第 4 月 | 内测 | 赶旺季（五一）前内测 50 家 | 旺季不出重复预订 |\n| 第 5 月 | 公测 | 民宿圈推广 | 注册 300 家 |\n| 第 6 月 | 商业化 | 付费上线 + P1 功能 | 付费 100 家，MRR ¥1 万 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 |\n|------|----------|\n| 注册民宿 | ≥500 |\n| 付费民宿 | ≥120 |\n| MRR | ¥12,000 |\n| 旺季重复预订率 | <1%（使用产品后）|\n| NPS | ≥42 |\n| 月续费率 | ≥88% |\n\n## 10. 风险与应对\n\n| 风险 | 等级 | 应对策略 |\n|------|------|--------|\n| 民宿主学习成本高（文化程度不一）| 高 | 视频教程+微信一对一指导，操作不超过 4 步 |\n| 农村网络不稳定 | 高 | PWA 离线缓存+页面极致轻量化 |\n| 旺季系统压力（全国同时发请求）| 中 | 提前压测，弹性扩容准备 |\n| OTA 平台竞争（美团推出类似功能）| 中 | 主打自营私域，与 OTA 互补而非竞争 |\n| 民宿行业政策风险（许可证要求）| 低 | 关注政策，产品不涉及资质认证，风险低 |',
'[{"step":"定位","decision":"自营私域预订管理，非OTA竞争","reason":"美团途家有流量优势无法竞争，帮民宿主把自己的私域客户管理好才是差异化空间"},{"step":"技术","decision":"微信小程序+H5双端，针对农村网络优化","reason":"农家乐老板重度微信用户，小程序门槛最低；农村4G网络不稳定需要特别优化"},{"step":"MVP时机","decision":"内测必须赶上五一旺季","reason":"旺季是农家乐最大的管理痛点，旺季实测数据是最强的产品验证"},{"step":"产品设计","decision":"操作不超过4步","reason":"民宿主文化水平参差不齐，极简是唯一可行的设计方向"},{"step":"定价","decision":"99元/月，免费版≤10间房","reason":"免费版吸引中小农家乐试用，99元换取旺季不再出错的价值远超付费成本"}]',
'submitted', 48, NOW() - INTERVAL '32 days', NOW() - INTERVAL '33 days', NOW() - INTERVAL '32 days'),

(9, 10, E'# 民宿管家云 - 乡村民宿智能预订管理平台\n\n## 1. 产品概述\n\n民宿管家云是一款专为 10-30 间房中小规模农家乐和乡村民宿设计的 SaaS 预订管理系统。产品以「让每间房都被聪明地管理」为核心价值，通过智能房态可视化、自助预订门户、自动化退改流程和旺季智能排期四大核心能力，帮助民宿主从「被微信和电话淹没」的混乱状态转向「系统化、自动化」的专业运营。\n\n**特色功能：旺季智能排期**。系统根据历年数据和当前预订情况，自动推荐节假日最优的最短入住天数和预订截止时间，最大化旺季收益。\n\n**市场机会窗口**：后疫情时代乡村旅游持续爆发，但农家乐数字化工具严重匮乏，2024 年是进入这一市场的最佳时机。\n\n## 2. 市场分析\n\n| 维度 | 数据 | 含义 |\n|------|------|------|\n| 乡村旅游年收入 | 超 1.5 万亿元（2023）| 巨大市场基础 |\n| 农家乐/乡村民宿数 | 约 180 万家 | 庞大用户基础 |\n| 10-30 间房目标市场 | 约 38 万家 | 有付费能力 |\n| 节假日入住率 | 近乎 100% | 旺季管理需求急迫 |\n| 民宿数字化工具渗透 | <5% | 蓝海市场 |\n| 旺季日均电话咨询量 | 平均每家 20-50 个 | 沟通效率瓶颈大 |\n| 民宿主年收入 | 20-200 万元 | 有 SaaS 付费能力 |\n\n**增长驱动因素**：\n1. 国家政策大力支持乡村旅游（文旅部十四五规划）\n2. 城市中产对「慢生活」需求持续增长\n3. 小红书/抖音内容带动，流量向优质农家乐集中\n4. 疫情后「周边游」习惯固化，本地农家乐受益\n\n## 3. 竞品矩阵\n\n| 产品 | 核心功能 | 价格 | 适合中小民宿 | 自营预订 | 弱网适配 |\n|------|---------|------|------------|---------|--------|\n| 途家 PMS | OTA 联动管理 | 抽佣+月费 | 中 | 弱 | 无 |\n| 客栈管家 | 客栈预订管理 | ¥198/月 | 高 | 有 | 无 |\n| 订单来了 | 民宿渠道管理 | ¥188/月 | 中 | 有 | 无 |\n| 美团民宿后台 | 平台内管理 | 抽佣 | 高 | 无 | 无 |\n| **民宿管家云** | **自营+智能排期** | **¥99/月** | **极高** | **✅** | **✅** |\n\n**竞品分析结论**：客栈管家是最接近的竞品，但定价偏高（¥198/月），且无弱网优化和旺季智能排期功能。民宿管家云以更低价格提供专属功能。\n\n## 4. 目标用户画像\n\n### 画像 A：「农村创业型」民宿主 - 赵大姐\n- **基本信息**：44 岁，湖南张家界，靠景区旺季收入，20 间房\n- **旺季特征**：黄金周一天接 50 个询问，自己和老公忙不过来\n- **最大困扰**：有客人多次预订了同一间房（因为微信聊天太混乱），造成纠纷\n- **核心诉求**：\n  1. 客人自己选房间，自己预订，不用通过微信\n  2. 每间房的预订情况一目了然\n  3. 客人取消要提前说，不然押金不退\n- **使用设备**：只有手机，从不用电脑\n- **学习意愿**：低，需要立竿见影的简单工具\n- **付费**：99 元/月可以接受，年付最好有优惠\n\n### 画像 B：「返乡创业」年轻民宿主 - 陈俊\n- **年龄**：28 岁，四川成都郊区，大学毕业后返乡开民宿，15 间房\n- **现状**：在小红书和美团都有运营，有自己的老客户群\n- **痛点**：\n  1. 美团和自营两套系统分开管，经常忘记同步房态\n  2. 旺季复购客户想给优惠，但没有工具\n  3. 想要数据分析，了解哪个时段、哪类客人最多\n- **付费意愿**：¥199/月，需要有报表功能\n- **产品诉求**：有一定功能，但操作不繁琐\n\n### 画像 C：「民宿集群」运营者 - 刘建国\n- **年龄**：40 岁，浙江千岛湖，旗下 3 家农家乐（共 50 间房）\n- **核心痛点**：三家店分别由三个亲戚管，他要统一调度，但信息不对称\n- **核心需求**：\n  1. 三家店房态统一展示\n  2. 跨店调配（A 店满了，推荐客人去 B 店）\n  3. 统计各店收入和入住率\n- **付费意愿**：每店 ¥79/月，三店合计 ¥237\n\n## 5. 核心功能设计\n\n### P0 - MVP\n\n| 功能 | 核心场景 | 关键指标 |\n|------|---------|--------|\n| 可视化房态日历 | 民宿主扫一眼知道今天/未来哪些房空着 | 数据加载 <2 秒（弱网）|\n| 客户自助预订 H5 | 客人扫二维码/点链接，自己选房+预订 | 预订完成率 ≥80% |\n| 预订冲突检测 | 同一房间同一日期第二次预订时自动拒绝 | 冲突率 0% |\n| 自动退改规则 | 民宿主设置退款政策，客人自助操作 | 退改处理时间 <5 分钟 |\n\n### P1 - 一期\n\n| 功能 | 价值 | 实现方式 |\n|------|------|--------|\n| 旺季智能排期 | 节假日自动建议最短入住天数 | 基于历史数据 + 规则引擎 |\n| 客户消息推送 | 预订确认/入住提醒/退房提醒自动发送 | 微信模板消息+短信 |\n| 押金管理 | 记录押金金额，退还状态追踪 | 手工记账+提醒 |\n| 民宿介绍页 | 可定制的民宿展示页，展示房型+价格+评价 | 静态页面生成器 |\n\n### P2 - 二期\n\n| 功能 | 描述 |\n|------|------|\n| OTA 双向同步 | 美团/途家房态与自营同步 |\n| 复购客户营销 | 旺季前推送老客优惠 |\n| 收入报表 | 月度入住率、收入分析 |\n| 多店统一管理 | 连锁农家乐 |\n\n## 6. 技术架构\n\n```\n核心挑战：农村弱网环境下的可用性\n\n前端（弱网优化）：\n  - 民宿主管理端：微信小程序（Service Worker 缓存）\n  - 客户预订：Next.js 15 SSG（静态生成，CDN 加速）\n  - 图片懒加载 + WebP 格式压缩\n  - 核心数据本地缓存，断网时可查看\n\n后端：\n  - API：Go + Echo v4（高性能，低内存占用）\n  - 冲突检测：数据库悲观锁（防止并发重复预订）\n  - 消息队列：Redis Streams（批量通知异步处理）\n  - 定时任务：Go cron\n\n存储：\n  - PostgreSQL 16\n  - Redis 7\n  - CDN 图片加速（阿里云 CDN）\n\n可用性：\n  - 99.9% SLA\n  - 多可用区部署\n  - 数据每日备份\n```\n\n**并发预订安全**：旺季高峰期，多个客户可能同时预订同一房间。使用 PostgreSQL SELECT FOR UPDATE 悲观锁 + Redis 分布式锁双重保障，确保零冲突。\n\n## 7. 商业模式\n\n| 版本 | 月费 | 年费 | 房间限制 | 核心功能 |\n|------|------|------|---------|--------|\n| 免费版 | ¥0 | ¥0 | ≤8 间 | 基础房态+预订链接 |\n| 标准版 | ¥99/月 | ¥890/年 | ≤30 间 | 全 P0+P1 功能 |\n| 专业版 | ¥199/月 | ¥1,790/年 | ≤60 间 | 全功能+OTA 同步+报表 |\n| 多店版 | ¥79/家/月（≥3 家）| - | 不限 | 标准版+统一看板 |\n\n## 8. MVP 路线图\n\n| 里程碑 | 时间 | 关键产出 | 验收标准 |\n|-------|------|---------|--------|\n| 用户调研 | 第 1 月 | 访谈 20 家，原型设计 | 功能列表锁定 |\n| MVP 开发 | 第 2-3 月 | P0 功能+弱网优化 | 内测可用 |\n| 旺季内测 | 第 4 月 | 赶五一旺季，50 家内测 | 重复预订 0 次 |\n| 公测推广 | 第 5 月 | 民宿圈口碑传播 | 注册 400 家 |\n| 商业化 | 第 6 月 | 付费功能+P1 功能 | MRR ¥1.2 万 |\n\n## 9. 成功指标\n\n| 指标 | 目标（6 个月）|\n|------|-------------|\n| 注册民宿 | ≥600 |\n| 付费民宿 | ≥150 |\n| MRR | ¥14,000 |\n| 旺季重复预订率 | <0.5% |\n| 月续费率 | ≥87% |\n| NPS | ≥45 |\n\n## 10. 风险与应对\n\n| 风险 | 等级 | 应对 |\n|------|------|------|\n| 弱网环境导致使用体验差 | 高 | PWA 离线缓存+极致轻量化是核心技术要求 |\n| 民宿主上手困难 | 高 | 视频教程+微信客服，操作步骤 ≤3 步 |\n| 旺季并发导致重复预订 | 高 | 数据库锁+Redis 分布式锁双重保障 |\n| 途家/美团推出私域工具 | 中 | 提前占领市场，口碑是护城河 |\n| 季节性收入（旺季才用）| 中 | P1 增加淡季营销功能，提升全年使用频次 |',
'[{"step":"核心特色","decision":"旺季智能排期为差异化功能","reason":"民宿主最大的收益损失来自旺季管理不当（未设最短天数导致碎片化预订），智能排期解决这一高价值问题"},{"step":"技术挑战","decision":"弱网优化作为核心技术要求","reason":"农家乐多在山区，4G不稳定是现实，产品如果在弱网下不好用，农家乐主根本不会用"},{"step":"安全设计","decision":"数据库悲观锁+Redis分布式锁","reason":"旺季并发预订是最可能导致产品失败的技术问题，必须在架构层面解决零冲突"},{"step":"MVP时机","decision":"赶五一旺季内测","reason":"旺季场景是最强的产品验证机会，旺季数据是最有说服力的推广素材"},{"step":"定价","decision":"99元/月，免费版8间房","reason":"农家乐主价格敏感，免费版够小农家乐用，99元对20间房的中等农家乐性价比极高"},{"step":"多店策略","decision":"多店版按家优惠定价","reason":"农家乐连锁是增长路径，多店折扣促进连锁农家乐采用，提升ARPU"}]',
'submitted', 53, NOW() - INTERVAL '24 days', NOW() - INTERVAL '25 days', NOW() - INTERVAL '24 days'),

(9, 16, E'# 房满满 - 农家乐数字化预订管理系统\n\n## 1. 产品概述\n\n房满满是一款专为农家乐和乡村民宿打造的预订管理微信小程序，以「让每一个空房变成收入」为产品使命。通过房态智能看板、一键分享预订二维码和自动化退改流程，帮助民宿主将旺季管理效率提升 3 倍，同时在淡季通过智能营销工具提升入住率。\n\n**产品哲学**：农家乐老板是中国最朴实的创业者，他们不需要「炫酷的功能」，他们需要的是「手机用用就能少接几十个电话」。房满满就是这样一款工具。\n\n**首发市场**：云南大理、浙江莫干山、四川峨眉山、贵州黔东南四个热门乡村旅游目的地聚焦渗透，口碑扩散。\n\n## 2. 市场分析\n\n| 指标 | 数据 | 分析 |\n|------|------|------|\n| 乡村旅游市场规模 | 1.5 万亿元（2023）| 增速 15%，持续高增 |\n| 农家乐/民宿总量 | 约 180 万家 | 目标人群基数大 |\n| 10-30 间房中规模民宿 | 约 38 万家 | 有付费意愿和能力 |\n| 民宿工具数字化率 | <5% | 蓝海，先发优势显著 |\n| 五一黄金周入住率 | >95%（热门景区周边）| 旺季管理瓶颈严重 |\n| 民宿主人均管理时间浪费 | 旺季 3-5 小时/天 | 管理效率低下 |\n| 因管理问题导致的退款纠纷 | 约 8-12%（估算）| 损失口碑和营收 |\n\n**精准目标市场画像**：年收入 20-100 万元、10-30 间房、有稳定复购客群但缺乏系统管理工具的中等规模农家乐/民宿。这类民宿有明确的管理痛点和付费能力，是最理想的目标客户。\n\n## 3. 竞品矩阵\n\n| 竞品 | 特点 | 月费 | 弱点 |\n|------|------|------|------|\n| 客栈管家 | 功能全面，有 PMS | ¥198/月 | 偏贵，小农家乐负担重 |\n| 订单来了 | 渠道管理为主 | ¥188/月 | 重 OTA 管理，轻私域 |\n| 美团民宿 | 平台流量大 | 抽佣 | 平台依赖，无私域能力 |\n| 途家管理 | 连锁民宿 | 抽佣+月费 | 门槛高 |\n| **房满满** | **微信生态专属** | **¥88/月** | **新品牌** |\n\n**核心竞争策略**：以比客栈管家便宜 55% 的价格、专注私域预订场景，快速获取价格敏感的中小农家乐用户。\n\n## 4. 目标用户画像\n\n### 画像 A：「景区周边」旺季依赖型民宿 - 张秀芬\n- **年龄**：47 岁，云南大理，苍山洱海景区旁，22 间客房\n- **旺季特征**：五一和国庆各 10 天，几乎满房，剩余时间入住率 30%\n- **旺季最大问题**：每年都出现「一间房被两个客人都付了定金」的情况，处理起来非常麻烦\n- **淡季问题**：不知道怎么让老客户再来一次\n- **技术水平**：会微信，会拍抖音，不会用复杂软件\n- **付费意愿**：¥88/月，旺季不出事就值\n\n### 画像 B：「网红民宿」运营者 - 胡昊\n- **年龄**：30 岁，浙江莫干山，精品设计民宿，13 间房，小红书 2 万粉\n- **当前工具**：飞书自建了一个预订表格，但维护成本高\n- **核心需求**：\n  1. 客人通过小红书链接直接预订，不用私信确认\n  2. 对接美团途家，房态统一管理\n  3. 复购客户自动发送优惠券\n- **付费意愿**：¥198/月，需要数据报表\n\n### 画像 C：「家庭农庄」综合体 - 李老板\n- **年龄**：50 岁，四川眉山，农家乐+采摘+餐饮一体，28 间房\n- **特殊需求**：客户不只订住宿，还要预约采摘和餐饮，三个服务要协调\n- **核心诉求**：住宿+采摘+餐饮三合一的预订管理\n- **付费意愿**：¥150-200/月（综合功能版）\n\n## 5. 核心功能设计\n\n### P0 - MVP（7 周）\n\n| 功能 | 具体能力 | 设计要点 |\n|------|---------|--------|\n| 智能房态看板 | 月视图/周视图，每间房的预订状态色块显示 | 5 秒内看懂，单手操作 |\n| 预订二维码生成 | 民宿主一键生成专属预订二维码，客人扫码预订 | 二维码永久有效，可打印张贴 |\n| 在线预订表单 | 客人选择日期+房型+人数，提交预订 | H5 表单，无需安装 App |\n| 冲突拦截 | 已预订房间同日期二次预订时，自动提示客人已满 | 0 冲突是核心承诺 |\n\n### P1 - 一期\n\n| 功能 | 价值 | 开发周期 |\n|------|------|--------|\n| 自动通知（预订确认/入住提醒/退房）| 减少重复沟通 | 2 周 |\n| 退改规则执行 | 民宿主设置政策，系统自动执行 | 2 周 |\n| 旺季特殊规则（最短天数/禁止日期）| 旺季收益最大化 | 1 周 |\n| 老客户微信通知 | 旺季前提醒老客户提前预订 | 2 周 |\n\n### P2 - 二期\n\n| 功能 | 商业价值 |\n|------|--------|\n| OTA 房态同步 | 解决多平台冲突，对接美团途家 |\n| 收入数据报表 | 月度入住率/收入分析 |\n| 采摘/餐饮预约 | 面向综合农庄的扩展场景 |\n| 多店管理 | 连锁农家乐统一看板 |\n\n## 6. 技术架构\n\n```\n架构设计：微信生态深度整合，农村可用性优先\n\n前端：\n  - 民宿主管理：微信小程序（主要入口）\n  - 客人预订：H5 网页（CDN 加速，≤2 秒首屏）\n  - 离线能力：小程序缓存预订数据，断网也能查看\n\n后端：\n  - API 服务：Go + Gin（轻量高性能）\n  - 预订引擎：PostgreSQL + 行级锁（防并发冲突）\n  - 通知系统：微信模板消息（主）+ 短信（备）\n  - 定时任务：cron（入住提醒 D-1、退房提醒当日 8:00）\n\n存储：\n  - PostgreSQL 16\n  - Redis（会话+防重提交）\n  - 腾讯云 COS（图片，与微信同一厂商）\n\n特别优化：\n  - 弱网下降级方案：纯文本模式（关闭图片）\n  - 图片全部 WebP + CDN\n  - H5 页面 ≤200KB（首屏）\n```\n\n## 7. 商业模式\n\n| 版本 | 月价 | 年价 | 房间上限 |\n|------|------|------|--------|\n| 免费 | ¥0 | ¥0 | ≤10 间 |\n| 基础版 | ¥88/月 | ¥790/年 | ≤30 间 |\n| 专业版 | ¥168/月 | ¥1,500/年 | ≤60 间 + OTA 同步 |\n| 旗舰版 | ¥268/月 | ¥2,400/年 | 无限 + 多店 + 报表 |\n\n**首年目标**：覆盖 4 大核心目的地，500 家付费民宿，MRR 5 万元。\n\n## 8. MVP 路线图\n\n| 时间节点 | 里程碑 | 验收 |\n|---------|-------|------|\n| 第 1 月 | 调研 + 原型 | 20 家民宿访谈完成 |\n| 第 2-3 月 | 开发 | P0 功能上线 |\n| 第 4 月 | 内测 | 目标地区 50 家内测 |\n| 第 5 月 | 旺季验证 | 五一数据验证产品价值 |\n| 第 6 月 | 商业化 | 付费转化，MRR ¥8,000 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 |\n|------|----------|\n| 注册民宿 | ≥600 |\n| 付费民宿 | ≥160 |\n| MRR | ¥16,000 |\n| 处理预订冲突率 | ≤0.5% |\n| NPS | ≥44 |\n| 月续费率 | ≥88% |\n\n## 10. 风险与应对\n\n| 风险 | 级别 | 对策 |\n|------|------|------|\n| 微信小程序功能限制 | 高 | H5 作为完整功能备选，小程序作为轻量入口 |\n| 弱网下体验差 | 高 | 极致轻量化+离线缓存，弱网降级方案 |\n| 旺季高并发冲突 | 高 | 行级锁+Redis 防重复提交 |\n| 民宿主学习成本 | 高 | 张贴二维码=核心操作，最低学习门槛 |\n| OTA 平台封杀私域 | 中 | 合法合规的私域运营，不违反 OTA 条款 |',
'[{"step":"产品哲学","decision":"以朴实为核心，不追求功能多","reason":"农家乐老板不需要炫酷功能，只需要少接几十个电话，产品哲学决定设计方向"},{"step":"首发策略","decision":"聚焦四大热门目的地","reason":"大理、莫干山、峨眉山、黔东南是最高浓度的目标用户聚集地，口碑传播效率高"},{"step":"核心功能","decision":"预订二维码是MVP核心","reason":"二维码可以打印张贴，是最低门槛的客户自助预订入口，农家乐老板无需做任何操作，客人扫码自助完成"},{"step":"定价","decision":"88元/月，比主要竞品便宜55%","reason":"价格敏感市场，低价是快速获客的关键，配合免费版10间房的门槛"},{"step":"技术","decision":"腾讯云COS+微信生态体系","reason":"民宿主重度微信用户，与微信同一厂商的云服务整合最顺畅"}]',
'submitted', 37, NOW() - INTERVAL '19 days', NOW() - INTERVAL '20 days', NOW() - INTERVAL '19 days'),

(9, 25, E'# 宿好 - 乡村民宿轻量化预订管理工具\n\n## 1. 产品概述\n\n宿好（StayGood）是一款专注解决农家乐和乡村民宿「旺季预订混乱」核心痛点的轻量级 SaaS。产品以「五分钟上手，旺季不再手忙脚乱」为品牌承诺，通过极简房态看板、扫码预订和自动化通知，帮助民宿主在不改变微信使用习惯的前提下，实现预订管理的数字化升级。\n\n**产品特色**：宿好首创「民宿码」概念——每家民宿生成一个永久专属二维码，民宿主打印后张贴在门口或发给客人，客人扫码即可查看实时房态并在线预订。极简到「一码搞定预订」。\n\n## 2. 市场分析\n\n| 数据维度 | 数值 | 战略含义 |\n|---------|------|--------|\n| 乡村旅游年总人次 | 25 亿次 | 持续高增长 |\n| 全国乡村民宿数量 | 约 180 万家 | 巨大基础市场 |\n| 中等规模（10-30 间）| 约 36 万家 | 核心目标群体 |\n| 节假日满房率 | >90%（热门目的地）| 管理需求急迫 |\n| 国家政策支持 | 文旅部「乡村旅游提质升级」| 利好行业发展 |\n| 现有数字化工具使用 | <5% | 蓝海机会 |\n| 民宿主平均旺季每天接电话 | 20-60 个 | 效率损耗严重 |\n\n**调研发现**（访谈 30 家民宿主）：\n- 90% 表示旺季期间「被微信消息和电话搞得焦头烂额」\n- 75% 发生过至少一次重复预订事故\n- 85% 愿意用一个简单的工具解决这个问题\n- 65% 愿意为此每月付 100 元以内的费用\n\n## 3. 竞品矩阵\n\n| 产品 | 定位 | 月费 | 上手难度 | 私域能力 | 弱网适配 |\n|------|------|------|---------|---------|--------|\n| 客栈管家 | 专业 PMS | ¥198 | 中 | 有 | 无 |\n| 订单来了 | 渠道管理 | ¥188 | 中 | 弱 | 无 |\n| 途家云 PMS | OTA 联动 | 抽佣 | 高 | 弱 | 无 |\n| 小程序自建 | 定制开发 | 5-20 万（一次性）| 低（用起来）| 好 | 无 |\n| **宿好** | **私域预订专属** | **¥79/月** | **极低** | **好** | **✅** |\n\n**定价策略**：以最低价格（¥79/月）进入市场，快速占领价格敏感的中小民宿市场，再通过功能升级推动付费升级。\n\n## 4. 目标用户画像\n\n### 画像 A：「旺季苦主」普通民宿主 - 陈阿姨\n- **年龄**：55 岁，江西婺源，传统徽派民宿，18 间房\n- **旺季经历**：每年春季赏花旺季（2-4 月）一天要处理 30-50 个预订询问，手机都发烫\n- **最糟糕的经历**：有一次微信太多消息，把同一间房订给了两个客人，其中一个当场要求赔偿\n- **对工具的期待**：「只要扫个码就能订，我少接几十个电话」\n- **付费底线**：79 元/月可以接受，有点贵就算了\n- **决策方式**：邻居/同行推荐，不会主动搜索\n\n### 画像 B：「转型升级」第二代民宿主 - 吴子豪\n- **年龄**：24 岁，父母开农家乐，他回来接手并升级\n- **目标**：把父母的农家乐从「纯散客」升级为「私域老客」运营模式\n- **需求**：\n  1. 在线预订（不依赖 OTA 平台）\n  2. 老客户营销（节假日前推优惠）\n  3. 数据分析（了解哪个季节、哪个渠道效果最好）\n- **付费意愿**：¥199/月（进阶版）\n- **产品影响力**：他是推动父母使用新工具的「内部推手」\n\n### 画像 C：「旺季错峰」休闲度假民宿 - 刘总\n- **年龄**：42 岁，广东清远，周末度假民宿，25 间房，主营周末和节假日\n- **特点**：客人主要是广州深圳来的城市白领，习惯在线预订\n- **痛点**：旺季周末一次性来 20 组客人同时询问，微信根本回不过来\n- **核心诉求**：客人自己能在线选房、看价格、付定金\n- **付费意愿**：¥128/月，需要有在线支付功能\n\n## 5. 核心功能设计\n\n### P0 - MVP（6 周交付）\n\n| 功能 | 核心价值 | 关键设计 |\n|------|---------|--------|\n| 民宿码（专属二维码）| 一码搞定客人预订入口 | 永久有效，可下载打印，适合张贴 |\n| 实时房态展示 | 客人扫码看到实时空闲情况 | 15 秒内加载（弱网），色块展示 |\n| 在线预订表单 | 客人自助填写预订信息 | 4 个字段（姓名/手机/入住日期/退房日期），最简设计 |\n| 预订冲突防护 | 同一房间同日期只能订一次 | 数据库原子操作保证 |\n\n### P1 - 一期（第 3 个月上线）\n\n| 功能 | 价值 | 技术方案 |\n|------|------|--------|\n| 自动确认通知 | 预订成功后自动通知客人和民宿主 | 微信服务通知+短信 |\n| 退改规则 | 民宿主设置，客人自助操作 | 规则引擎 + 状态机 |\n| 旺季排期规则 | 节假日设置最短入住天数/特殊价格 | 日历规则编辑器 |\n| 复购客户提醒 | 旺季前自动推送老客优惠 | 定时任务+短信 |\n\n### P2 - 二期（5-6 个月后）\n\n| 功能 | 描述 |\n|------|------|\n| 在线支付（定金）| 微信支付接入，预订时收定金 |\n| OTA 同步 | 美团/途家双向房态同步 |\n| 数据报表 | 入住率/收入/来源分析 |\n| 多店管理 | 连锁统一看板 |\n\n## 6. 技术架构\n\n```\n架构原则：能用微信原生能力的就用，自研部分极致精简\n\n客户端：\n  - 民宿主：微信小程序（主管理端）\n  - 客户预订：H5（扫码后跳转，无需安装）\n\n服务端：\n  - API：Go + Gin（轻量）\n  - 核心锁：PostgreSQL FOR UPDATE SKIP LOCKED（防冲突）\n  - 消息：微信模板消息 + 阿里云短信\n  - 定时：Go cron\n\n存储：\n  - PostgreSQL 16（主数据）\n  - Redis（会话+去重）\n  - CDN（图片+静态资源）\n\n弱网优化清单：\n  ✅ H5 首屏 ≤150KB\n  ✅ 图片 WebP + 懒加载\n  ✅ 小程序 Service Worker 缓存\n  ✅ API 超时 5 秒内返回\n  ✅ 降级模式（无图纯文本）\n```\n\n## 7. 商业模式\n\n| 层级 | 价格 | 适用场景 |\n|------|------|--------|\n| 免费版 | ¥0/月 | ≤8 间房，基础预订 |\n| 标准版 | ¥79/月 或 ¥699/年 | ≤30 间房，全 P0+P1 |\n| 进阶版 | ¥159/月 或 ¥1,390/年 | ≤60 间+OTA 同步+报表 |\n| 旗舰版 | ¥259/月 | 无限+多店+在线支付+API |\n\n**核心定价逻辑**：以业界最低价（¥79）进入，先做大用户规模，再通过 P2 功能（在线支付、OTA 同步）推动升级到进阶版（¥159）。\n\n## 8. MVP 路线图\n\n| 阶段 | 时间 | 目标 | 关键任务 |\n|------|------|------|--------|\n| 调研 | 第 1 月 | 30 家民宿访谈 | 确认 P0 功能列表 |\n| 开发 | 第 2-3 月 | MVP 交付 | 民宿码+实时房态+预订+冲突防护 |\n| 内测 | 第 4 月 | 旺季前内测 50 家 | 婺源春季赏花旺季验证 |\n| 推广 | 第 5 月 | 民宿主社群口碑传播 | 目标注册 500 家 |\n| 商业化 | 第 6 月 | 付费转化 + P1 上线 | MRR ¥10,000 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 |\n|------|----------|\n| 注册民宿 | ≥700 |\n| 付费民宿 | ≥180 |\n| MRR | ¥16,000 |\n| 预订冲突发生率 | <0.2% |\n| 月续费率 | ≥88% |\n| NPS | ≥46 |\n\n## 10. 风险与应对\n\n| 风险 | 等级 | 应对 |\n|------|------|------|\n| 民宿主推广意愿低 | 高 | 民宿码可以打印张贴，是最低门槛的推广工具 |\n| 弱网导致预订失败 | 高 | 前端极致轻量+错误重试机制 |\n| 旺季高峰并发冲突 | 高 | PostgreSQL FOR UPDATE + Redis 分布式锁 |\n| 定价过低，难以为继 | 中 | P2 高价功能（支付/OTA）提升 ARPU |\n| 民宿主换工具成本 | 中 | 老预订数据可 Excel 导入，降低迁移成本 |',
'[{"step":"核心创新","decision":"创造民宿码概念","reason":"将预订入口实体化为二维码，民宿主打印张贴后无需做任何操作，客人扫码自助完成，是最低门槛的推广方式"},{"step":"定价策略","decision":"以79元/月行业最低价进入","reason":"快速占领价格敏感的中小民宿市场，先做规模，再通过高价值P2功能提升ARPU"},{"step":"首发目的地","decision":"婺源春季赏花旺季作为首个验证场景","reason":"婺源每年2-4月是全国知名旺季，民宿管理压力极大，是最强烈的需求验证场景"},{"step":"技术","decision":"弱网优化清单作为核心技术要求","reason":"农家乐很多在信号不好的山区，弱网可用性是产品能否在目标场景使用的基础"},{"step":"商业化路径","decision":"免费→79元→159元渐进升级","reason":"以最低价获客，再通过在线支付和OTA同步功能推动升级，符合SaaS渐进商业化逻辑"}]',
'submitted', 62, NOW() - INTERVAL '15 days', NOW() - INTERVAL '16 days', NOW() - INTERVAL '15 days');

