-- IDEA 10: 房产经纪带看记录 - Author 6
-- ============================================================
INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(10, 6, E'# 带看助手 - 房产经纪人智能带看管理工具\n\n## 1. 产品概述\n\n带看助手是一款专为月带看 20-50 组客户的二手房经纪人设计的移动端 SaaS 工具，核心解决「客户偏好记录混乱、跟进状态不清、成交漏斗分析缺失」三大痛点。经纪人通过带看助手可以在带看结束后 5 分钟内完成客户信息录入、自动生成带看报告，并获得 AI 驱动的跟进建议，显著提升成交转化率。\n\n**核心价值**：帮助经纪人从「靠感觉」做销售，升级为「靠数据」做决策。\n\n**市场机会**：二手房市场月均带看量超 5000 万次，但 95% 以上的经纪人仍靠微信和记忆管理客户，严重依赖个人经验，缺乏系统化的客户管理工具。\n\n## 2. 市场分析\n\n| 指标 | 数据 | 来源/说明 |\n|------|------|----------|\n| 全国二手房经纪人数量 | 约 150 万 | 国家住建部 2023 |\n| 月带看 20 单以上活跃经纪人 | 约 45 万 | 估算活跃比例 30% |\n| 经纪人月均佣金收入 | 1-5 万元 | 一线城市 |\n| 带看成交转化率（行业均值）| 约 3-5% | 即 30 组带看成 1-2 单 |\n| 提升 1% 转化率对应月均增收 | 约 5,000-15,000 元 | 高 ROI 场景 |\n| 经纪人使用专属 CRM 工具 | <8% | 大多用微信/备忘录 |\n| 目标市场 TAM | 约 2.7 亿元/年 | 45 万 × 600 元/年 |\n\n**核心洞察**：经纪人最宝贵的资产是客户关系，但现有工具（链家/安居客后台）只管房源，不管客户关系。带看助手填补「客户关系管理」这一关键空白。\n\n## 3. 竞品矩阵\n\n| 产品 | 定位 | 月费 | 客户管理 | 带看记录 | 转化分析 | 独立性 |\n|------|------|------|---------|---------|---------|-------|\n| 链家 CRM（平台内置）| 平台工具 | 免费（平台内）| 弱 | 无 | 无 | 无（数据属平台）|\n| 安居客经纪人端 | 平台工具 | 免费 | 弱 | 无 | 无 | 无 |\n| 销售易（企业 CRM）| 通用销售 | ¥200+/人 | 强 | 无（无带看概念）| 强 | ✅ |\n| 企业微信 SCRM | 私域管理 | ¥200+/人 | 中 | 无 | 弱 | ✅ |\n| 自建微信文件夹 | 无工具 | 免费 | 无 | 无 | 无 | ✅ |\n| **带看助手** | **经纪人专属** | **¥99/月** | **强（专属）**| **✅（核心功能）**| **✅** | **✅** |\n\n**结论**：平台工具不做客户管理（平台利益冲突），通用 CRM 不懂带看场景，市场存在明显空白。\n\n## 4. 目标用户画像\n\n### 画像 A：「业绩导向」精英经纪人 - 刘勇\n- **基本信息**：31 岁，北京链家经纪人，从业 5 年，月均带看 35 组\n- **月收入**：2-4 万元（佣金制）\n- **当前工具**：微信 + 印象笔记自制带看记录模板\n- **核心痛点**：\n  1. 35 个客户同时跟进，很难记清楚每个人的具体需求\n  2. 带看后过了 3 天想跟进，但忘了客户看了什么房子，说了什么\n  3. 不知道自己「哪种客户」转化率高，无法优化策略\n- **对工具的期待**：「让我知道应该优先跟进哪个客户」\n- **付费意愿**：99-150 元/月，只要能多成一单就回本\n\n### 画像 B：「新手上路」初级经纪人 - 小王\n- **年龄**：23 岁，从业 8 个月，上海某中介公司\n- **月带看量**：20 组左右，成交率低于均值\n- **核心困扰**：\n  1. 带看时记录了很多，但回来整理要花 2 小时，效率低\n  2. 不知道客户是「真有意向」还是「随便看看」\n  3. 跟进时机把握不准，要么太频繁被嫌弃，要么太久被遗忘\n- **对工具期望**：能给我提示「什么时候该联系客户」「说什么比较好」\n- **付费意愿**：79-99 元/月（能提升成交率就值）\n\n### 画像 C：「团队管理」门店经理 - 张经理\n- **年龄**：38 岁，门店经理，管理 12 名经纪人\n- **痛点**：\n  1. 不知道团队成员的带看量和跟进状态\n  2. 客户资源在经纪人个人手机里，人离职资源就带走了\n  3. 想分析团队整体的带看→成交漏斗\n- **付费意愿**：团队版 ¥599/月（12 人），不贵\n\n## 5. 核心功能设计\n\n### P0 - MVP\n\n| 功能 | 用户价值 | 关键设计点 |\n|------|---------|----------|\n| 带看快速录入 | 带看结束后 5 分钟内完成记录 | 语音输入+预置标签，减少打字 |\n| 客户偏好画像 | 自动聚合每次带看的客户偏好 | 户型/楼层/价格/学区等标签 |\n| 跟进状态管理 | 7 个状态追踪客户进度 | 待跟进/跟进中/意向强/谈价/签约/成交/流失 |\n| 跟进提醒 | 设置跟进时间，到期提醒 | 微信服务通知+App 推送 |\n\n### P1 - 一期迭代\n\n| 功能 | 价值 | 优先级理由 |\n|------|------|----------|\n| AI 跟进建议 | 根据客户偏好和状态给出下次跟进的话术建议 | 新手痛点，差异化功能 |\n| 成交漏斗分析 | 各阶段转化率可视化，找到瓶颈 | 帮经纪人优化策略 |\n| 房源推荐匹配 | 新房源上线时，自动匹配偏好符合的客户 | 高频价值场景 |\n| 带看报告生成 | 一键生成带看情况报告，发给客户 | 提升经纪人专业形象 |\n\n### P2 - 后续规划\n\n| 功能 | 描述 |\n|------|------|\n| 团队管理看板 | 门店经理查看团队带看量和转化数据 |\n| 客户共享与防撞单 | 团队内客户信息共享，防止多人联系同一客户 |\n| 成交客户转介绍追踪 | 老客户介绍新客户的关系链管理 |\n| 市场行情推送 | 经纪人关注的小区价格波动自动推送 |\n\n## 6. 技术架构\n\n```\n架构原则：手机端优先，AI 能力核心化\n\n前端：\n  - 经纪人端：React Native（iOS + Android 原生 App，手机使用高频场景）\n  - Web 端：React 18（门店经理管理后台）\n\n后端：\n  - API：Go + Echo v4（RESTful）\n  - AI 服务：Python FastAPI（NLP 跟进建议，调用 OpenAI/国产大模型）\n  - 推荐引擎：简单协同过滤（房源-客户偏好匹配）\n  - 定时任务：Go cron（跟进提醒、房源匹配推送）\n\n存储：\n  - PostgreSQL 16（用户和业务数据）\n  - Redis（缓存+会话）\n  - Elasticsearch（房源搜索和匹配）\n\n第三方：\n  - 微信服务通知（提醒主通道）\n  - Apple/Google Push（App 推送备用）\n  - 语音转文字（科大讯飞 API，带看记录语音输入）\n```\n\n## 7. 商业模式\n\n| 版本 | 月价 | 年价 | 功能 | 目标用户 |\n|------|------|------|------|--------|\n| 基础版 | ¥99/月 | ¥890/年 | P0+P1 核心功能，1 人使用 | 个人经纪人 |\n| 专业版 | ¥159/月 | ¥1,390/年 | 全功能+AI 建议+漏斗分析 | 精英经纪人 |\n| 团队版 | ¥49/人/月（≥5 人）| ¥430/人/年 | 专业版+团队看板+客户共享 | 门店/团队 |\n\n**盈亏测算**：\n- 固定成本（服务器+AI API）：约 8,000 元/月\n- 盈亏平衡：需约 80 个基础版付费用户\n\n## 8. MVP 路线图\n\n| 阶段 | 时间 | 目标 | 成功标准 |\n|------|------|------|--------|\n| 调研 | 第 1 月 | 访谈 25 名经纪人，确认核心需求 | PRD 锁定 |\n| 开发 | 第 2-3 月 | P0 功能 + React Native App | 内测可用 |\n| 内测 | 第 4 月 | 30 名经纪人内测 | 7 日留存 >55% |\n| 公测 | 第 5 月 | 房产经纪社群推广 | 注册 500 |\n| 商业化 | 第 6 月 | 付费转化 + P1 上线 | 付费 100，MRR 1 万 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 |\n|------|----------|\n| 注册经纪人 | ≥800 |\n| 付费经纪人 | ≥120 |\n| MRR | ¥12,000 |\n| 带看记录条数 | >20,000 |\n| 用户平均成交转化率提升 | ≥15%（相比使用前）|\n| NPS | ≥45 |\n\n## 10. 风险与应对\n\n| 风险 | 等级 | 应对策略 |\n|------|------|--------|\n| 平台（链家/贝壳）推出类似功能 | 高 | 主打独立性和跨平台，强调「数据属于你自己」|\n| 经纪人学习成本高 | 高 | 语音输入+预置标签极大简化录入，5 分钟上手 |\n| AI 建议质量不达预期 | 中 | P1 上线后分 AB 组测试，持续迭代模型质量 |\n| 竞品快速跟进 | 中 | 数据积累和 AI 模型是护城河，先发优势明显 |\n| 月流失率高（季节性）| 中 | 年付优惠 + 成交数据报告增强留存 |',
'[{"step":"核心定位","decision":"客户关系管理而非房源管理","reason":"平台工具都做房源管理，客户关系管理是空白，也是经纪人最大的效率损耗来源"},{"step":"MVP功能","decision":"语音录入+预置标签是核心体验","reason":"经纪人带看后疲惫，复杂录入会导致放弃使用，语音+标签将录入时间降至5分钟"},{"step":"AI策略","decision":"AI跟进建议放在P1而非P0","reason":"AI功能需要数据积累才能有质量，P0先积累数据，P1再引入AI建议"},{"step":"团队版","decision":"团队版按人头定价","reason":"门店经理购买决策，按人头定价让经理清楚团队成本，也有助于团队版推广"},{"step":"技术","decision":"React Native做原生App","reason":"经纪人在外带看时全靠手机，原生App体验比H5好很多，语音录入需要原生能力"}]',
'submitted', 58, NOW() - INTERVAL '35 days', NOW() - INTERVAL '36 days', NOW() - INTERVAL '35 days'),

(10, 12, E'# 房客宝 - 经纪人带看与客户跟进管理系统\n\n## 1. 产品概述\n\n房客宝是一款专为二手房经纪人打造的移动端客户管理工具，以「让每次带看都成为成交的垫脚石」为产品使命。通过结构化带看记录、客户意向评分、智能跟进提醒和成交漏斗可视化，帮助月带看 20-50 组客户的经纪人系统化地管理客户关系，将带看成交转化率从行业均值 3-5% 提升至 7-10%。\n\n**核心差异化**：房客宝首创「带看意向评分」系统——通过带看时记录的 8 个维度数据（价格契合度/户型满意度/交通满意度/决策紧迫度等），自动计算客户成交概率评分（0-100 分），让经纪人清晰知道「应该重点跟进哪些客户」。\n\n## 2. 市场分析\n\n| 维度 | 数据 | 战略意义 |\n|------|------|--------|\n| 全国房产经纪人 | 约 150 万 | 庞大用户基础 |\n| 活跃经纪人（月带看 20+）| 约 45 万 | 核心目标市场 |\n| 经纪人平均月收入 | 8,000-50,000 元 | 高付费意愿 |\n| 行业平均带看成交率 | 3-5% | 提升空间大 |\n| 客户管理工具使用率 | <8% | 市场教育机会 |\n| 经纪人日均客户跟进时间 | 2-4 小时 | 效率损耗大 |\n| 链家/贝壳平台市占率 | 约 50%（一线城市）| 非平台经纪人仍有 50% |\n\n**市场动态**：2024 年二手房市场持续活跃（特别是核心城市），经纪人竞争加剧，数据驱动的经纪人与靠经验的经纪人业绩差距扩大，工具驱动的专业化是必然趋势。\n\n## 3. 竞品矩阵\n\n| 产品 | 功能重点 | 适合经纪人 | 月价 | 带看记录 | 意向评分 | 数据独立 |\n|------|---------|----------|------|---------|---------|--------|\n| 链家工作台 | 平台内 CRM | 链家经纪人 | 免费 | 无 | 无 | ❌（数据属平台）|\n| 贝壳找房后台 | 房源管理 | 贝壳经纪人 | 免费 | 无 | 无 | ❌ |\n| 销售易 | 通用销售 CRM | 低（无带看概念）| ¥150+/月 | 无 | 无 | ✅ |\n| 纷享销客 | 企业 CRM | 低 | ¥100+/月 | 无 | 无 | ✅ |\n| **房客宝** | **经纪人专属** | **极高** | **¥99/月** | **✅**（核心功能）| **✅**（首创）| **✅** |\n\n## 4. 目标用户画像\n\n### 画像 A：「数据型」精英经纪人 - 陈薇\n- **基本信息**：29 岁，上海，链家经纪人，从业 4 年\n- **月带看量**：40-50 组\n- **当前做法**：用 Excel 自制了一个客户跟进表，但维护很麻烦\n- **核心痛点**：\n  1. 40 个客户同时跟进，优先级判断很难，经常凭感觉\n  2. 知道某个客户有意向，但不知道上次谈到哪里了\n  3. 想分析自己的成交规律，但数据都散落在聊天记录里\n- **对产品期望**：「告诉我今天应该优先联系哪几个客户」\n- **付费意愿**：月付 128-159 元，只要能多成一单\n\n### 画像 B：「成长型」新手经纪人 - 孟浩\n- **年龄**：24 岁，郑州，独立经纪人（非平台）\n- **月带看量**：20-25 组，成交率低\n- **核心困扰**：不知道带看后怎么跟进，经常在错误的时间用错误的方式联系客户\n- **需求**：\n  1. 系统告诉我「这个客户评分高，明天应该主动联系」\n  2. 跟进话术建议（不知道说什么）\n  3. 知道哪些客户意向降低了（及时止损）\n- **付费**：99 元/月，如果真能提高成交率\n\n### 画像 C：「管理型」门店负责人 - 李总\n- **年龄**：42 岁，成都，独立中介门店，8 名经纪人\n- **痛点**：\n  1. 不知道每个经纪人的带看质量和跟进状态\n  2. 好的经纪人离职，客户资源全带走\n  3. 团队整体转化率低，不知道从哪里优化\n- **需求**：团队版，管理员可以看所有人的带看和跟进数据\n- **付费**：团队版 ¥400-600/月（8 人）\n\n## 5. 核心功能设计\n\n### P0 - MVP（8 周）\n\n| 功能 | 核心价值 | 关键技术 |\n|------|---------|--------|\n| 带看快速录入（语音+标签）| 5 分钟完成一次带看记录 | 科大讯飞语音 API + 预置标签体系 |\n| 8 维意向评分系统 | 自动计算客户成交概率 | 加权评分算法（价格/户型/交通/紧迫度等）|\n| 客户看板（按评分排序）| 一眼看出应该优先跟进谁 | 卡片式 UI，支持拖拽调整优先级 |\n| 跟进提醒设置 | 到期提醒，不遗漏任何客户 | 微信服务通知+App Push |\n\n### P1 - 一期（第 3-4 个月）\n\n| 功能 | 价值 | 实现方式 |\n|------|------|--------|\n| AI 跟进话术建议 | 根据客户状态给出下次沟通建议 | 调用大模型 API，基于带看记录生成 |\n| 成交转化漏斗 | 经纪人自己的转化率分析 | 按漏斗阶段统计，可视化 |\n| 房源推荐匹配 | 新房源自动匹配符合偏好的客户 | 规则引擎（标签匹配）|\n| 带看报告生成 | 专业带看报告一键发给客户 | PDF 生成，微信分享 |\n\n### P2 - 二期\n\n| 功能 | 价值 |\n|------|------|\n| 团队数据看板 | 门店经理查看团队整体数据 |\n| 防撞单系统 | 团队内客户分配，避免重复联系 |\n| 转介绍追踪 | 老客户介绍的关系链管理 |\n| 市场行情推送 | 经纪人关注小区的成交动态 |\n\n## 6. 技术架构\n\n```\n移动优先 + AI 增强架构\n\n前端：\n  - 经纪人 App：React Native（iOS + Android）\n    - 带看录入：语音+标签混合输入\n    - 离线支持：本地 SQLite 缓存，无网也能录入\n  - 管理 Web：React 18（门店经理）\n\n后端：\n  - 核心 API：Go + Echo v4\n  - AI 服务：Python FastAPI（意向评分模型 + 话术建议）\n  - 模型：微调的通义千问（阿里国产，合规）\n  - 推荐：标签匹配引擎\n  - 定时：Go cron（跟进提醒、房源匹配推送）\n\n存储：\n  - PostgreSQL 16（主数据）\n  - Redis（会话+缓存）\n  - SQLite（客户端离线缓存）\n\n第三方 API：\n  - 科大讯飞（语音识别）\n  - 阿里通义千问（AI 建议）\n  - 极光推送（App Push）\n  - 微信服务通知（微信提醒）\n```\n\n**意向评分算法**（8 维加权）：\n- 价格契合度（权重 25%）\n- 户型满意度（20%）\n- 决策紧迫度（20%）\n- 预算匹配度（15%）\n- 交通满意度（10%）\n- 配套满意度（5%）\n- 带看态度（3%）\n- 家庭决策一致性（2%）\n\n## 7. 商业模式\n\n| 版本 | 月价 | 年价（85折）| 功能 | 定位 |\n|------|------|-----------|------|------|\n| 试用版 | 免费 14 天 | - | 全功能 | 降低试用门槛 |\n| 基础版 | ¥99/月 | ¥1,010/年 | P0 全部，P1 部分 | 个人经纪人 |\n| 专业版 | ¥159/月 | ¥1,620/年 | 全功能（AI 建议+漏斗+报告）| 精英经纪人 |\n| 团队版 | ¥45/人/月（≥5 人）| ¥460/人/年 | 专业+团队看板+防撞单 | 中介门店 |\n\n## 8. MVP 路线图\n\n| 里程碑 | 时间 | 目标 |\n|-------|------|------|\n| 调研 | 第 1 月 | 访谈 30 名经纪人，确认功能列表 |\n| 开发 | 第 2-4 月 | P0 功能 + React Native App |\n| 内测 | 第 5 月 | 50 名经纪人内测，收集评分准确度反馈 |\n| 公测 | 第 6 月 | 房产中介社群推广 |\n| 商业化 | 第 7 月 | 付费转化，P1 功能上线 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 |\n|------|----------|\n| 注册经纪人 | ≥1,000 |\n| 付费经纪人 | ≥150 |\n| MRR | ¥18,000 |\n| 带看记录量 | >30,000 条 |\n| 意向评分准确率（高分成交率）| ≥65% |\n| NPS | ≥50 |\n\n## 10. 风险与应对\n\n| 风险 | 影响 | 概率 | 应对 |\n|------|------|------|------|\n| 平台推出竞品 | 高 | 中 | 强调数据独立性，数据属于经纪人本人 |\n| AI 评分不准，失去信任 | 高 | 中 | MVP 阶段显示置信度，主动标注「参考值」，持续优化 |\n| 经纪人录入意愿低 | 高 | 高 | 语音录入+一键标签，把录入时间压缩到 5 分钟以内 |\n| 客户数据隐私风险 | 中 | 低 | 清晰的隐私条款，数据加密，不对外出售 |\n| 房市下行影响付费意愿 | 中 | 中 | 市场越难，工具价值越高；强调成本效益 |',
'[{"step":"核心功能","decision":"意向评分系统是最大差异化","reason":"经纪人最大的时间损耗是跟进策略不清，评分系统直接回答了最核心的问题：应该优先联系谁"},{"step":"技术","decision":"React Native原生App+离线支持","reason":"经纪人在外带看时常处于弱网环境，原生App+离线缓存确保随时可以录入"},{"step":"AI策略","decision":"意向评分P0上线，话术建议P1","reason":"评分模型可以基于规则先实现，不依赖大量数据；话术建议需要积累数据才有质量"},{"step":"定价","decision":"14天全功能免费试用","reason":"经纪人体验到意向评分的价值需要实际带看数据，14天试用足够完成3-5次带看"},{"step":"数据独立","decision":"强调数据属于经纪人本人","reason":"平台工具最大的弱点是数据属于平台，这是打动不在链家/贝壳的独立经纪人的核心话语"}]',
'submitted', 44, NOW() - INTERVAL '28 days', NOW() - INTERVAL '29 days', NOW() - INTERVAL '28 days'),

(10, 18, E'# 看房通 - 房产经纪人移动端带看管理工具\n\n## 1. 产品概述\n\n看房通是面向月带看 20-50 组客户的二手房经纪人设计的移动端 SaaS，以「帮经纪人把带看资产变成成交资本」为核心价值主张。产品通过「带看记录→客户画像→智能跟进→成交分析」四步闭环，帮助经纪人将每次带看的有效信息转化为可追踪、可分析的客户资产，系统化提升成交转化率。\n\n**产品独特价值**：看房通不只是记录工具，更是经纪人的「成交教练」——通过分析历史带看数据，告诉经纪人哪类客户更容易成交、什么跟进节奏效果最好，用数据帮助经纪人持续优化销售策略。\n\n## 2. 市场分析\n\n| 指标 | 数值 | 备注 |\n|------|------|------|\n| 全国房产经纪人 | 约 150 万 | 住建部数据 |\n| 月带看 20+ 的活跃经纪人 | 约 45 万 | 占全部约 30% |\n| 经纪人平均月佣金收入 | 1.5-6 万元 | 一二线城市 |\n| 带看→成交平均转化率 | 3-5% | 行业均值 |\n| 成交转化率提升 2% 的月均增收 | 约 10,000-30,000 元 | 高价值场景 |\n| 经纪人使用专属工具比例 | <8% | 几乎空白 |\n| 目标 TAM | 约 2.7 亿/年 | 有大量改进空间 |\n\n**竞争环境分析**：大平台（链家/贝壳/安居客）的工具都聚焦于房源管理和客源匹配，对「经纪人个人客户关系管理」普遍忽视，且平台工具的数据归平台所有。这为独立工具提供了明确的市场切口。\n\n## 3. 竞品矩阵\n\n| 竞品 | 定位 | 带看场景适配 | 数据归属 | 月价 | 主要不足 |\n|------|------|------------|---------|------|--------|\n| 链家工作台 | 平台内 CRM | 中 | 平台 | 免费 | 数据不属于经纪人 |\n| 销售易 | 通用 CRM | 低 | 用户 | ¥150+ | 无带看专属功能 |\n| 企业微信 SCRM | 私域管理 | 低 | 用户 | ¥200+ | 无带看概念 |\n| 自制 Excel/表格 | 无工具 | 低（低效）| 用户 | 免费 | 无自动化、无分析 |\n| **看房通** | **经纪人专属** | **极高** | **用户自有** | **¥99/月** | **新品牌** |\n\n## 4. 目标用户画像\n\n### 画像 A：「独立经纪人」高手 - 周磊\n- **年龄**：33 岁，深圳，独立经纪人（非平台员工），从业 7 年\n- **月带看量**：45 组（带看量大，个人口碑好）\n- **最大的管理挑战**：客户量太大，跟进依靠记忆，经常出现「跟进过度」（一个客户 3 天打 5 个电话）或「跟进遗漏」（一个意向客户 2 周没联系）\n- **对数据的态度**：非常希望有工具分析「我哪类客户成交率高」\n- **期望功能**：客户优先级排序+跟进时间建议+成交分析\n- **付费意愿**：¥128-160/月\n\n### 画像 B：「平台经纪人」成长中 - 宋晓\n- **年龄**：26 岁，北京我爱我家员工，从业 2 年\n- **现状**：用公司系统管房源，用微信管客户，两边信息不同步\n- **核心痛点**：\n  1. 带看后记录在哪里？微信备忘录，时间长了自己都找不到\n  2. 客户买了别家的房子，自己都不知道，一直在浪费时间跟进\n  3. 什么时候该催、什么时候该等，不知道如何判断\n- **使用场景**：带看结束后在车里（或地铁上）快速录入\n- **付费**：¥99/月可接受\n\n### 画像 C：「门店经理」管理角色 - 华总\n- **年龄**：45 岁，南京，独立中介门店，10 名经纪人\n- **核心问题**：\n  1. 不知道每个经纪人的带看质量（数量多但成交少）\n  2. 优质客户信息在经纪人手机里，离职后全部流失\n  3. 团队整体转化率不知道，也不知道怎么提高\n- **使用场景**：管理后台查看团队数据，周会时用来分析\n- **团队规模付费**：10 人 × ¥45 = ¥450/月\n\n## 5. 核心功能设计\n\n### P0 - MVP\n\n| 功能 | 用户痛点对应 | 核心设计 |\n|------|------------|--------|\n| 带看快速录入 | 记录散乱，靠记忆 | 语音转文字 + 8 类预置标签，3 分钟内完成 |\n| 客户意向状态 | 优先级不清 | 5 状态：冷淡/关注/感兴趣/意向/成交 |\n| 跟进时间设定 | 跟进遗漏 | 设置下次跟进时间，到期 Push 提醒 |\n| 带看历史查询 | 记录找不到 | 按客户/时间/状态快速搜索 |\n\n### P1 - 一期（第 3-4 月上线）\n\n| 功能 | 经纪人价值 | 差异化程度 |\n|------|---------|----------|\n| 客户成交概率模型 | 科学判断哪些客户应该重点跟进 | 高（核心差异化）|\n| 成交漏斗分析 | 找到自己销售流程的最大瓶颈 | 高 |\n| 跟进节奏建议 | AI 建议下次联系时间和话题 | 高 |\n| 带看周报自动生成 | 自动生成本周带看情况总结 | 中 |\n\n### P2 - 二期\n\n| 功能 | 价值 |\n|------|------|\n| 团队管理看板 | 门店经理查看团队整体数据 |\n| 客户资产防流失 | 经纪人离职后，客户数据归还门店 |\n| 房源偏好匹配 | 新房源上线自动推送给匹配客户 |\n| 竞品动态追踪 | 关注小区的成交价格走势 |\n\n## 6. 技术架构\n\n```\n设计原则：极速录入 + 准确分析 + 移动优先\n\n客户端：\n  - 经纪人 App：Flutter（iOS+Android 一套代码，跨平台一致体验）\n    - 核心场景：带看后在车里/地铁 5 分钟内完成录入\n    - 离线支持：SQLite 本地缓存，同步到云端\n  - 管理端：Vue 3 + Ant Design（门店经理 PC 使用）\n\n服务端：\n  - RESTful API：Go + Echo v4\n  - 成交概率模型：Scikit-learn（基于历史带看数据训练逻辑回归模型）\n  - AI 话术：调用通义千问 API\n  - 消息推送：极光推送（App）+ 微信服务通知\n  - 定时服务：Go cron\n\n数据层：\n  - PostgreSQL 16（主数据）\n  - Redis（缓存+会话）\n  - 阿里云 PAI（模型训练和部署）\n```\n\n**成交概率模型技术方案**：初期（数据量 <5 万条）使用规则引擎（基于专家经验定义规则），中期（数据量 >5 万条）迁移到 Logistic Regression 模型，长期（数据量 >50 万条）引入更复杂的特征工程和模型。\n\n## 7. 商业模式\n\n| 版本 | 月价 | 年价（8 折）| 核心功能 |\n|------|------|-----------|--------|\n| 体验版 | 免费 14 天 | - | 全功能 |\n| 基础版 | ¥99/月 | ¥950/年 | P0 全部 |\n| 专业版 | ¥168/月 | ¥1,610/年 | 全功能（含 AI 分析）|\n| 团队版 | ¥45/人/月（≥5 人）| ¥430/人/年 | 专业版+团队管理 |\n\n**预计 12 个月 ARR**：\n- 个人版：300 人 × ¥130 均值 × 12 = ¥46.8 万\n- 团队版：20 家门店 × 8 人 × ¥45 × 12 = ¥86.4 万\n- 合计 ARR 约：¥133 万\n\n## 8. MVP 路线图\n\n| 阶段 | 时间 | 关键任务 |\n|------|------|--------|\n| 调研 | 第 1 月 | 30 名经纪人访谈，确认核心痛点 |\n| 开发 | 第 2-4 月 | Flutter App + Go 后端，P0 功能 |\n| 内测 | 第 5 月 | 50 名经纪人内测 |\n| 公测 | 第 6 月 | 房产经纪社群推广，目标注册 600 |\n| 商业化 | 第 7-8 月 | 付费转化 + P1 功能 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月目标 | 12 个月目标 |\n|------|----------|----------|\n| 注册经纪人 | ≥800 | ≥3,000 |\n| 付费经纪人 | ≥130 | ≥600 |\n| MRR | ¥15,000 | ¥70,000 |\n| 带看记录量 | >25,000 | >200,000 |\n| 成交率提升（使用用户）| ≥20% | ≥30% |\n| NPS | ≥48 | ≥55 |\n\n## 10. 风险与应对\n\n| 风险 | 严重度 | 对策 |\n|------|-------|------|\n| 大平台推出免费竞品 | 高 | 数据独立性是核心优势，数据归用户自己 |\n| 经纪人录入习惯难养成 | 高 | 语音+标签极速录入，App 每天 Push 提醒 |\n| AI 模型早期数据不足 | 高 | 冷启动使用规则引擎，积累数据后切换模型 |\n| 房市下行，经纪人减少 | 中 | 行情差时工具价值更高（提升成交率），留住用户 |\n| Flutter 开发效率低 | 低 | 考虑 React Native 替代，技术选型可调整 |',
'[{"step":"技术选型","decision":"Flutter跨平台App","reason":"一套代码覆盖iOS+Android，减少开发成本，经纪人群体iOS和Android均有分布"},{"step":"AI冷启动","decision":"规则引擎先行，积累数据后切换ML模型","reason":"AI模型需要大量数据才准确，冷启动用专家规则提供基础价值，不因数据不足影响早期用户体验"},{"step":"核心卖点","decision":"成交教练定位","reason":"经纪人不只需要记录工具，更需要提升成交率的方法论，成交教练定位比记录工具溢价更高"},{"step":"数据独立","decision":"强调数据归属用户","reason":"平台CRM最大的弱点是数据属于平台，这是打动大量在平台以外工作的独立经纪人的核心理由"},{"step":"团队版","decision":"离职客户资产防流失是关键功能","reason":"这是门店经理愿意付费的最强动机：经纪人离职不再意味着客户流失"}]',
'submitted', 39, NOW() - INTERVAL '22 days', NOW() - INTERVAL '23 days', NOW() - INTERVAL '22 days'),

(10, 26, E'# 经纪宝 - 房产经纪人全链路客户管理系统\n\n## 1. 产品概述\n\n经纪宝是一款专为二手房经纪人设计的移动端客户管理 SaaS，以「用数据替代经验，用系统替代记忆」为产品使命。通过带看结构化记录、AI 驱动的客户意向分析、智能跟进建议和成交漏斗优化四大能力，帮助月带看 20-50 组的经纪人系统化地管理客户资产，将个人成交转化率提升 30-50%。\n\n**产品定位升级**：经纪宝不只是一个记录工具，而是经纪人的「AI 销售副驾」——在带看记录、客户分析、跟进策略三个关键环节提供 AI 辅助，让数字原生代经纪人相对老经纪人形成竞争优势。\n\n**一句话价值**：每次带看都值得被认真记录，因为下一单成交就藏在里面。\n\n## 2. 市场分析\n\n| 市场细分 | 规模 | 增速 | 工具渗透率 |\n|---------|------|------|----------|\n| 全国活跃经纪人（月带看 20+）| 约 45 万 | 8%/年 | <8% |\n| 一线城市经纪人（付费意愿强）| 约 12 万 | 5%/年 | <12% |\n| 独立经纪人（非大平台）| 约 20 万 | 12%/年 | <5% |\n| 中介门店（5 人以上）| 约 3 万家 | 6%/年 | <10% |\n\n**市场驱动因素**：\n1. 二手房市场竞争加剧，经纪人「专业化」是差异化关键\n2. 95 后经纪人进入市场，对数字化工具接受度高\n3. 客户对经纪人服务质量要求升级（期望「专业顾问」而非「信息中介」）\n4. 大平台抽佣高（贝壳 30-60%），独立经纪人有强烈建立私域的需求\n\n**TAM 计算**：45 万活跃经纪人 × 平均 ¥120/月 × 12 个月 = 约 **6.5 亿元/年**（比其他垂直市场大得多）\n\n## 3. 竞品矩阵\n\n| 竞品 | 类型 | 月价 | 带看记录 | AI 分析 | 数据归属 | 评分 |\n|------|------|------|---------|---------|---------|------|\n| 链家/贝壳 CRM | 平台内置 | 免费 | 无（基础）| 无 | 平台 | 4/10 |\n| 安居客经纪人端 | 平台工具 | 免费 | 无 | 无 | 平台 | 3/10 |\n| 销售易 | 通用 CRM | ¥150+/人 | 无专属 | 无 | 用户 | 5/10 |\n| HubSpot（国际）| 通用 CRM | $50+/人 | 无专属 | 弱 | 用户 | 4/10 |\n| 自制 Excel | 无工具 | 免费 | 手动 | 无 | 用户 | 2/10 |\n| **经纪宝** | **经纪人专属 AI CRM** | **¥99** | **✅专属** | **✅核心** | **用户** | **9/10** |\n\n## 4. 目标用户画像\n\n### 画像 A：「AI 拥抱型」年轻精英经纪人 - 徐飞\n- **基本信息**：27 岁，杭州，独立经纪人，月带看 40 组\n- **核心诉求**：\n  1. 快速录入带看信息（在去下一个带看的路上完成）\n  2. AI 自动分析客户成交概率（不靠感觉，靠数据）\n  3. AI 生成跟进话术（针对不同客户的个性化话术）\n- **付费意愿**：¥159/月，只要 AI 建议有用\n- **特征**：对 AI 工具高度感兴趣，愿意尝鲜，是口碑传播者\n\n### 画像 B：「经验驱动型」资深经纪人 - 马大姐\n- **年龄**：41 岁，武汉，从业 12 年，月带看 25 组\n- **对数字化态度**：不排斥，但需要证明有用\n- **核心诉求**：\n  1. 别让我忘了该打电话了（跟进提醒）\n  2. 客户信息系统化（不再靠记忆）\n  3. 我的老客户要维护好（复购/转介绍）\n- **付费意愿**：¥99/月，功能好用就不换\n- **特征**：决策慢但忠诚度高，一旦付费很少流失\n\n### 画像 C：「机构管理型」区域经理 - 孙明\n- **年龄**：38 岁，管理 15 人团队（两家门店）\n- **核心问题**：团队管理全靠每天早会口头汇报，没有数据\n- **需求**：\n  1. 每个经纪人的带看量和跟进状态\n  2. 团队整体成交漏斗分析\n  3. 防止经纪人「带走客户」（员工离职）\n- **付费**：¥600-900/月（15 人）\n\n## 5. 核心功能设计\n\n### P0 - MVP（7 周）\n\n| 功能 | 解决痛点 | 技术实现 |\n|------|---------|--------|\n| 语音+标签带看录入 | 记录慢、不完整 | 科大讯飞 ASR + 15 个预置标签 |\n| 客户意向 5 级评定 | 优先级判断混乱 | 冷淡/观望/感兴趣/意向强/谈判中 |\n| 带看历史时间线 | 记录找不到 | 按客户展示全部带看历史 |\n| 跟进提醒 | 遗漏跟进 | App Push + 微信服务通知双通道 |\n\n### P1 - 一期（3-4 个月后上线）\n\n| 功能 | AI 应用 | 产品价值 |\n|------|---------|--------|\n| 成交概率预测 | 逻辑回归模型（初期规则引擎）| 帮经纪人判断优先级 |\n| 个性化跟进话术 | 大模型（通义千问）| 针对客户状态生成话术 |\n| 成交漏斗分析 | 统计分析 | 找到个人销售瓶颈 |\n| 带看专业报告 | PDF 模板生成 | 提升经纪人专业形象 |\n\n### P2 - 二期\n\n| 功能 | 商业价值 |\n|------|--------|\n| 团队管理看板 | 面向门店经理，提升 ARPU |\n| 客户资产保护 | 离职后数据归门店，解决管理者痛点 |\n| 房源-客户智能匹配 | 新房源自动匹配有意向客户 |\n| 老客户复购追踪 | 提升 LTV，挖掘转介绍 |\n\n## 6. 技术架构\n\n```\n架构愿景：AI-first 经纪人工具\n\n客户端：\n  - 经纪人 App：React Native（iOS + Android）\n    - 带看录入：语音 ASR + 标签选择混合输入\n    - 离线缓存：AsyncStorage 本地存储，联网同步\n  - 管理端：React 18（门店经理 Web）\n\n服务端：\n  - 核心 API：Go + Echo v4\n  - AI 推理服务：Python FastAPI + 阿里云 PAI\n  - 消息服务：Go Worker + Redis Queue（批量推送）\n  - 定时任务：Go cron（跟进提醒扫描）\n\nAI 技术栈：\n  - 语音识别：科大讯飞实时 ASR（<500ms 响应）\n  - 意向评分：规则引擎（冷启动）→ Logistic Regression → Gradient Boosting（随数据增长迭代）\n  - 话术生成：通义千问 Turbo（低延迟，成本可控）\n\n存储：\n  - PostgreSQL 16（带看记录 + 客户数据）\n  - Redis 7（会话 + 热点缓存）\n  - 向量数据库 Milvus（未来语义搜索带看记录）\n```\n\n## 7. 商业模式\n\n| 版本 | 月费 | 年费（8.5折）| 核心功能 |\n|------|------|-----------|--------|\n| 免费体验 | 14 天全功能 | - | 验证价值 |\n| 个人版 | ¥99/月 | ¥1,010/年 | P0 全部功能 |\n| AI 版 | ¥168/月 | ¥1,714/年 | 全功能+AI 预测+话术 |\n| 团队版 | ¥49/人/月（≥5 人）| ¥500/人/年 | AI 版+团队看板+资产保护 |\n\n**AI API 成本控制**：话术生成按需调用，按经纪人实际使用量计费。控制每用户月 AI 成本 <¥5，保持健康毛利率。\n\n## 8. MVP 路线图\n\n| 时间 | 里程碑 | 验收标准 |\n|------|-------|--------|\n| 第 1 月 | 用户调研 30 人 + 线框图 | PRD v1.0 |\n| 第 2-4 月 | React Native App + Go 后端 | 内测 20 人可用 |\n| 第 5 月 | 内测扩大 + AI 评分冷启动 | 7 日留存 ≥55% |\n| 第 6 月 | 公测推广 | 注册 800 |\n| 第 7-8 月 | 商业化 + P1 AI 功能 | 付费 150，MRR 2 万 |\n\n## 9. 成功指标\n\n| 指标 | 6 个月 | 12 个月 |\n|------|--------|--------|\n| 注册经纪人 | 1,000 | 4,000 |\n| 付费经纪人 | 150 | 700 |\n| MRR | ¥18,000 | ¥90,000 |\n| 带看记录量 | >30,000 | >300,000 |\n| AI 建议采用率 | ≥45% | ≥60% |\n| NPS | ≥48 | ≥58 |\n\n## 10. 风险与应对\n\n| 风险 | 级别 | 应对策略 |\n|------|------|--------|\n| AI 冷启动质量差，失去信任 | 高 | 明确标注「规则建议」vs「AI 建议」，冷启动期降低预期 |\n| 大平台免费竞品 | 高 | 强调「数据属于你，不属于平台」，独立工具的核心价值 |\n| 录入习惯养成难 | 高 | 语音录入+极简界面，目标 3 分钟/次；前 14 天每日 Push 养成习惯 |\n| AI API 成本超预期 | 中 | 限速控制，免费版无 AI 功能，AI 版定价包含 AI 成本 |\n| 房地产市场波动 | 中 | 市场越难越需要工具提升效率，弱市是工具推广的好时机 |',
'[{"step":"产品定位升级","decision":"从记录工具升级为AI销售副驾","reason":"记录工具是低价值功能，AI分析才是高溢价服务，这个定位能支撑更高的定价和更强的付费动机"},{"step":"AI策略","decision":"三阶段AI能力演进：规则→ML→深度学习","reason":"冷启动无数据，规则引擎先满足基本需求；数据积累后切换到ML模型，长期建立数据壁垒"},{"step":"TAM重新估算","decision":"TAM为6.5亿，比其他赛道大得多","reason":"经纪人数量多、收入高、付费意愿强，这是值得All-in的赛道"},{"step":"核心差异","decision":"AI版定价168元，突出AI溢价","reason":"AI功能是经纪人愿意额外付费的核心，清晰的AI版定价让溢价可见"},{"step":"防流失","decision":"离职客户资产保护是团队版核心功能","reason":"这是门店经理购买团队版的最强动机，解决了经纪人离职带走客户的行业痛点"}]',
'submitted', 65, NOW() - INTERVAL '18 days', NOW() - INTERVAL '19 days', NOW() - INTERVAL '18 days');
